// Generated from ecma262/spec.html — do not edit by hand.
const sections = {"1":"<h2>Syntax</h2>\n    <pre class=\"emu-grammar\">Script :\n  ScriptBody?\n\nScriptBody :\n  StatementList[~Yield, ~Await, ~Return]</pre>\n\n    ","2":"<h2>Syntax</h2>\n    <pre class=\"emu-grammar\">Module :\n  ModuleBody?\n\nModuleBody :\n  ModuleItemList\n\nModuleItemList :\n  ModuleItem\n  ModuleItemList ModuleItem\n\nModuleItem :\n  ImportDeclaration\n  ExportDeclaration\n  StatementListItem[~Yield, +Await, ~Return]\n\nModuleExportName :\n  IdentifierName\n  StringLiteral</pre>\n\n    ","":"","1.1":"<pre class=\"emu-grammar\">Script : ScriptBody</pre>\n      <ul>\n        <li>\n          It is a Syntax Error if the LexicallyDeclaredNames of |ScriptBody| contains any duplicate entries.\n        </li>\n        <li>\n          It is a Syntax Error if any element of the LexicallyDeclaredNames of |ScriptBody| also occurs in the VarDeclaredNames of |ScriptBody|.\n        </li>\n      </ul>\n      <pre class=\"emu-grammar\">ScriptBody : StatementList</pre>\n      <ul>\n        <li>\n          It is a Syntax Error if |StatementList| Contains `super` unless the source text containing `super` is eval code that is being processed by a direct eval. Additional early error rules for `super` within direct eval are defined in 19.2.1.1.\n        </li>\n        <li>\n          It is a Syntax Error if |StatementList| Contains |NewTarget| unless the source text containing |NewTarget| is eval code that is being processed by a direct eval. Additional early error rules for |NewTarget| in direct eval are defined in 19.2.1.1.\n        </li>\n        <li>\n          It is a Syntax Error if ContainsDuplicateLabels of |StatementList| with argument « » is *true*.\n        </li>\n        <li>\n          It is a Syntax Error if ContainsUndefinedBreakTarget of |StatementList| with argument « » is *true*.\n        </li>\n        <li>\n          It is a Syntax Error if ContainsUndefinedContinueTarget of |StatementList| with arguments « » and « » is *true*.\n        </li>\n        <li>\n          It is a Syntax Error if AllPrivateIdentifiersValid of |StatementList| with argument « » is *false* unless the source text containing |ScriptBody| is eval code that is being processed by a direct eval.\n        </li>\n      </ul>\n    ","1.2":"<dl class=\"header\">\n      </dl>\n      <pre class=\"emu-grammar\">Script : ScriptBody?</pre>\n      <emu-alg><ol><li>If |ScriptBody| is present and the Directive Prologue of |ScriptBody| contains a Use Strict Directive, return *true*.</li><li>Return *false*.</li></ol></emu-alg>\n    ","1.3":"<pre class=\"emu-grammar\">Script : [empty]</pre>\n      <emu-alg><ol><li>Return *undefined*.</li></ol></emu-alg>\n    ","1.4":"<p>A <dfn id=\"script-record\" variants=\"Script Records\">Script Record</dfn> encapsulates information about a script being evaluated. Each script record contains the fields listed in table-script-records.</p>\n\n      <emu-table id=\"table-script-records\" caption=\"Script Record Fields\">\n        <table>\n          <thead>\n            <tr>\n              <th>\n                Field Name\n              </th>\n              <th>\n                Value Type\n              </th>\n              <th>\n                Meaning\n              </th>\n            </tr>\n          </thead>\n          <tr>\n            <td>\n              [[Realm]]\n            </td>\n            <td>\n              a Realm Record\n            </td>\n            <td>\n              The realm within which this script was created.\n            </td>\n          </tr>\n          <tr>\n            <td>\n              [[ECMAScriptCode]]\n            </td>\n            <td>\n              a |Script| Parse Node\n            </td>\n            <td>\n              The result of parsing the source text of this script.\n            </td>\n          </tr>\n          <tr>\n            <td>\n              [[LoadedModules]]\n            </td>\n            <td>\n              a List of LoadedModuleRequest Records\n            </td>\n            <td>\n              A map from the specifier strings imported by this script to the resolved Module Record. The list does not contain two different Records _r1_ and _r2_ such that ModuleRequestsEqual(_r1_, _r2_) is *true*.\n            </td>\n          </tr>\n          <tr>\n            <td>\n              [[HostDefined]]\n            </td>\n            <td>\n              anything (default value is ~empty~)\n            </td>\n            <td>\n              Field reserved for use by host environments that need to associate additional information with a script.\n            </td>\n          </tr>\n        </table>\n      </emu-table>\n    ","1.5":"<dl class=\"header\">\n        <dt>description</dt>\n        <dd>It creates a Script Record based upon the result of parsing _sourceText_ as a |Script|.</dd>\n      </dl>\n\n      <emu-alg><ol><li>Let _script_ be ParseText(_sourceText_, |Script|).</li><li>If _script_ is a List of errors, return _script_.</li><li>Return Script Record { [[Realm]]: _realm_, [[ECMAScriptCode]]: _script_, [[LoadedModules]]: « », [[HostDefined]]: _hostDefined_ }.</li></ol></emu-alg>\n      <emu-note>\n        <p>An implementation may parse script source text and analyse it for Early Error conditions prior to evaluation of ParseScript for that script source text. However, the reporting of any errors must be deferred until the point where this specification actually performs ParseScript upon that source text.</p>\n      </emu-note>\n    ","1.6":"<dl class=\"header\">\n      </dl>\n\n      <emu-alg><ol><li>Let _globalEnv_ be _scriptRecord_.[[Realm]].[[GlobalEnv]].</li><li>Let _scriptContext_ be a new ECMAScript code execution context.</li><li>Set the Function of _scriptContext_ to *null*.</li><li>Set the Realm of _scriptContext_ to _scriptRecord_.[[Realm]].</li><li>Set the ScriptOrModule of _scriptContext_ to _scriptRecord_.</li><li>Set the VariableEnvironment of _scriptContext_ to _globalEnv_.</li><li>Set the LexicalEnvironment of _scriptContext_ to _globalEnv_.</li><li>Set the PrivateEnvironment of _scriptContext_ to *null*.</li><li>Suspend the running execution context.</li><li>Push _scriptContext_ onto the execution context stack; _scriptContext_ is now the running execution context.</li><li>Let _script_ be _scriptRecord_.[[ECMAScriptCode]].</li><li>Let _result_ be Completion(GlobalDeclarationInstantiation(_script_, _globalEnv_)).</li><li>If _result_ is a normal completion, then<ol><li>Set _result_ to Completion(Evaluation of _script_).</li><li>If _result_ is a normal completion and _result_.[[Value]] is ~empty~, then<ol><li>Set _result_ to NormalCompletion(*undefined*).</li></ol></li></ol></li><li>Suspend _scriptContext_ and remove it from the execution context stack.</li><li>Assert: The execution context stack is not empty.</li><li>Resume the context that is now on the top of the execution context stack as the running execution context.</li><li>Return ? _result_.</li></ol></emu-alg>\n    ","1.7":"<dl class=\"header\">\n        <dt>description</dt>\n        <dd>_script_ is the |Script| for which the execution context is being established. _env_ is the global environment in which bindings are to be created.</dd>\n      </dl>\n      <emu-note>\n        <p>When an execution context is established for evaluating scripts, declarations are instantiated in the current global environment. Each global binding declared in the code is instantiated.</p>\n      </emu-note>\n      <p>It performs the following steps when called:</p>\n      <emu-alg><ol><li>Let _lexNames_ be the LexicallyDeclaredNames of _script_.</li><li>Let _varNames_ be the VarDeclaredNames of _script_.</li><li>For each element _name_ of _lexNames_, do<ol><li>If HasLexicalDeclaration(_env_, _name_) is *true*, throw a *SyntaxError* exception.</li><li>Let _hasRestrictedGlobal_ be ? HasRestrictedGlobalProperty(_env_, _name_).</li><li>NOTE: Global `var` and `function` bindings (except those that are introduced by non-strict direct eval) are non-configurable and are therefore restricted global properties.</li><li>If _hasRestrictedGlobal_ is *true*, throw a *SyntaxError* exception.</li></ol></li><li>For each element _name_ of _varNames_, do<ol><li>If HasLexicalDeclaration(_env_, _name_) is *true*, throw a *SyntaxError* exception.</li></ol></li><li>Let _varDeclarations_ be the VarScopedDeclarations of _script_.</li><li>Let _functionsToInitialize_ be a new empty List.</li><li>Let _declaredFunctionNames_ be a new empty List.</li><li>For each element _varDecl_ of _varDeclarations_, in reverse List order, do<ol><li>If _varDecl_ is not either a |VariableDeclaration|, a |ForBinding|, or a |BindingIdentifier|, then<ol><li>Assert: _varDecl_ is either a |FunctionDeclaration|, a |GeneratorDeclaration|, an |AsyncFunctionDeclaration|, or an |AsyncGeneratorDeclaration|.</li><li>NOTE: If there are multiple function declarations for the same name, the last declaration is used.</li><li>Let _fn_ be the sole element of the BoundNames of _varDecl_.</li><li>If _declaredFunctionNames_ does not contain _fn_, then<ol><li>Let _fnDefinable_ be ? CanDeclareGlobalFunction(_env_, _fn_).</li><li>If _fnDefinable_ is *false*, throw a *TypeError* exception.</li><li>Append _fn_ to _declaredFunctionNames_.</li><li>Insert _varDecl_ as the first element of _functionsToInitialize_.</li></ol></li></ol></li></ol></li><li>Let _declaredVarNames_ be a new empty List.</li><li>For each element _varDecl_ of _varDeclarations_, do<ol><li>If _varDecl_ is either a |VariableDeclaration|, a |ForBinding|, or a |BindingIdentifier|, then<ol><li>For each String _vn_ of the BoundNames of _varDecl_, do<ol><li>If _declaredFunctionNames_ does not contain _vn_, then<ol><li>Let _vnDefinable_ be ? CanDeclareGlobalVar(_env_, _vn_).</li><li>If _vnDefinable_ is *false*, throw a *TypeError* exception.</li><li>If _declaredVarNames_ does not contain _vn_, then<ol><li>Append _vn_ to _declaredVarNames_.</li></ol></li></ol></li></ol></li></ol></li></ol></li><li>NOTE: No abnormal terminations occur after this algorithm step if the global object is an ordinary object. However, if the global object is a Proxy exotic object it may exhibit behaviours that cause abnormal terminations in some of the following steps.</li><li>If the host is a web browser or otherwise supports B.3.2, then<ol><li>Let _strict_ be ScriptIsStrict of _script_.</li><li>If _strict_ is *false*, then<ol><li>Let _declaredFunctionOrVarNames_ be the list-concatenation of _declaredFunctionNames_ and _declaredVarNames_.</li><li>For each |FunctionDeclaration| _f_ that is directly contained in the |StatementList| of any |Block|, |CaseClause|, or |DefaultClause| _x_ such that _script_ Contains _x_ is *true*, do<ol><li>Let _funcName_ be the StringValue of the |BindingIdentifier| of _f_.</li><li>If replacing the |FunctionDeclaration| _f_ with a |VariableStatement| that has _funcName_ as a |BindingIdentifier| would not produce any Early Errors for _script_, then<ol><li>If HasLexicalDeclaration(_env_, _funcName_) is *false*, then<ol><li>Let _fnDefinable_ be ? CanDeclareGlobalVar(_env_, _funcName_).</li><li>If _fnDefinable_ is *true*, then<ol><li>NOTE: A var binding for _funcName_ is only instantiated here if it is neither a VarDeclaredName nor the name of another |FunctionDeclaration|.</li><li>If _declaredFunctionOrVarNames_ does not contain _funcName_, then<ol><li>Perform ? CreateGlobalVarBinding(_env_, _funcName_, *false*).</li><li>Append _funcName_ to _declaredFunctionOrVarNames_.</li></ol></li><li>When the |FunctionDeclaration| _f_ is evaluated, perform the following steps in place of the |FunctionDeclaration| Evaluation algorithm provided in 15.2.6:<ol><li>Let _gEnv_ be the running execution context's VariableEnvironment.</li><li>Let _bEnv_ be the running execution context's LexicalEnvironment.</li><li>Let _fObj_ be ! _bEnv_.GetBindingValue(_funcName_, *false*).</li><li>Perform ? <emu-meta effects=\"user-code\">_gEnv_.SetMutableBinding(_funcName_, _fObj_, *false*)</emu-meta>.</li><li>Return ~unused~.</li></ol></li></ol></li></ol></li></ol></li></ol></li></ol></li></ol></li><li>Let _lexDeclarations_ be the LexicallyScopedDeclarations of _script_.</li><li>Let _privateEnv_ be *null*.</li><li>For each element _lexDecl_ of _lexDeclarations_, do<ol><li>NOTE: Lexically declared names are only instantiated here but not initialized.</li><li>For each element _dn_ of the BoundNames of _lexDecl_, do<ol><li>If IsConstantDeclaration of _lexDecl_ is *true*, then<ol><li>Perform ? <emu-meta effects=\"user-code\">_env_.CreateImmutableBinding(_dn_, *true*)</emu-meta>.</li></ol></li><li>Else,<ol><li>Perform ? <emu-meta effects=\"user-code\">_env_.CreateMutableBinding(_dn_, *false*)</emu-meta>.</li></ol></li></ol></li></ol></li><li>For each Parse Node _f_ of _functionsToInitialize_, do<ol><li>Let _fn_ be the sole element of the BoundNames of _f_.</li><li>Let _fo_ be InstantiateFunctionObject of _f_ with arguments _env_ and _privateEnv_.</li><li>Perform ? <emu-meta effects=\"user-code\">CreateGlobalFunctionBinding(_env_, _fn_, _fo_, *false*)</emu-meta>.</li></ol></li><li>For each String _vn_ of _declaredVarNames_, do<ol><li>Perform ? <emu-meta effects=\"user-code\">CreateGlobalVarBinding(_env_, _vn_, *false*)</emu-meta>.</li></ol></li><li>Return ~unused~.</li></ol></emu-alg>\n      <emu-note>\n        <p>Early errors specified in 16.1.1 prevent name conflicts between function/var declarations and let/const/class declarations as well as redeclaration of let/const/class bindings for declaration contained within a single |Script|. However, such conflicts and redeclarations that span more than one |Script| are detected as runtime errors during GlobalDeclarationInstantiation. If any such errors are detected, no bindings are instantiated for the script. However, if the global object is defined using Proxy exotic objects then the runtime tests for conflicting declarations may be unreliable resulting in an abrupt completion and some global declarations not being instantiated. If this occurs, the code for the |Script| is not evaluated.</p>\n        <p>Unlike explicit var or function declarations, properties that are directly created on the global object result in global bindings that may be shadowed by let/const/class declarations.</p>\n      </emu-note>\n    ","2.1":"","2.1.1":"<pre class=\"emu-grammar\">ModuleBody : ModuleItemList</pre>\n        <ul>\n          <li>\n            It is a Syntax Error if the LexicallyDeclaredNames of |ModuleItemList| contains any duplicate entries.\n          </li>\n          <li>\n            It is a Syntax Error if any element of the LexicallyDeclaredNames of |ModuleItemList| also occurs in the VarDeclaredNames of |ModuleItemList|.\n          </li>\n          <li>\n            It is a Syntax Error if the ExportedNames of |ModuleItemList| contains any duplicate entries.\n          </li>\n          <li>\n            It is a Syntax Error if any element of the ExportedBindings of |ModuleItemList| does not also occur in either the VarDeclaredNames of |ModuleItemList|, or the LexicallyDeclaredNames of |ModuleItemList|.\n          </li>\n          <li>\n            It is a Syntax Error if |ModuleItemList| Contains `super`.\n          </li>\n          <li>\n            It is a Syntax Error if |ModuleItemList| Contains |NewTarget|.\n          </li>\n          <li>\n            It is a Syntax Error if ContainsDuplicateLabels of |ModuleItemList| with argument « » is *true*.\n          </li>\n          <li>\n            It is a Syntax Error if ContainsUndefinedBreakTarget of |ModuleItemList| with argument « » is *true*.\n          </li>\n          <li>\n            It is a Syntax Error if ContainsUndefinedContinueTarget of |ModuleItemList| with arguments « » and « » is *true*.\n          </li>\n          <li>\n            It is a Syntax Error if AllPrivateIdentifiersValid of |ModuleItemList| with argument « » is *false*.\n          </li>\n        </ul>\n        <emu-note>\n          <p>The duplicate ExportedNames rule implies that multiple `export default` |ExportDeclaration| items within a |ModuleBody| is a Syntax Error. Additional error conditions relating to conflicting or duplicate declarations are checked during module linking prior to evaluation of a |Module|. If any such errors are detected the |Module| is not evaluated.</p>\n        </emu-note>\n        <pre class=\"emu-grammar\">ModuleExportName : StringLiteral</pre>\n        <ul>\n          <li>It is a Syntax Error if IsStringWellFormedUnicode(SV of |StringLiteral|) is *false*.</li>\n        </ul>\n      ","2.1.2":"<dl class=\"header\">\n          <dt>description</dt>\n          <dd>It creates a List of all of the local name bindings defined by _importEntries_.</dd>\n        </dl>\n        <emu-alg><ol><li>Let _localNames_ be a new empty List.</li><li>For each ImportEntry Record _i_ of _importEntries_, do<ol><li>Append _i_.[[LocalName]] to _localNames_.</li></ol></li><li>Return _localNames_.</li></ol></emu-alg>\n      ","2.1.3":"<p>A <dfn id=\"modulerequest-record\" variants=\"ModuleRequest Records\">ModuleRequest Record</dfn> represents the request to import a module with given import attributes. It consists of the following fields:</p>\n        <emu-table id=\"table-modulerequest-fields\" caption=\"ModuleRequest Record Fields\">\n          <table>\n            <tr>\n              <th>\n                Field Name\n              </th>\n              <th>\n                Value Type\n              </th>\n              <th>\n                Meaning\n              </th>\n            </tr>\n            <tr>\n              <td>\n                [[Specifier]]\n              </td>\n              <td>\n                a String\n              </td>\n              <td>\n                The module specifier\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[Attributes]]\n              </td>\n              <td>\n                a List of ImportAttribute Records\n              </td>\n              <td>\n                The import attributes\n              </td>\n            </tr>\n          </table>\n        </emu-table>\n\n        <p>A <dfn id=\"loadedmodulerequest-record\" variants=\"LoadedModuleRequest Records\">LoadedModuleRequest Record</dfn> represents the request to import a module together with the resulting Module Record. It consists of the same fields defined in table table-modulerequest-fields, with the addition of [[Module]]:</p>\n        <emu-table id=\"table-loadedmodulerequest-fields\" caption=\"LoadedModuleRequest Record Fields\">\n          <table>\n            <tr>\n              <th>\n                Field Name\n              </th>\n              <th>\n                Value Type\n              </th>\n              <th>\n                Meaning\n              </th>\n            </tr>\n            <tr>\n              <td>\n                [[Specifier]]\n              </td>\n              <td>\n                a String\n              </td>\n              <td>\n                The module specifier\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[Attributes]]\n              </td>\n              <td>\n                a List of ImportAttribute Records\n              </td>\n              <td>\n                The import attributes\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[Module]]\n              </td>\n              <td>\n                a Module Record\n              </td>\n              <td>\n                The loaded module corresponding to this module request\n              </td>\n            </tr>\n          </table>\n        </emu-table>\n\n        <p>An <dfn id=\"importattribute-record\" variants=\"ImportAttribute Records\">ImportAttribute Record</dfn> consists of the following fields:</p>\n        <emu-table id=\"table-importattribute-fields\" caption=\"ImportAttribute Record Fields\">\n          <table>\n            <tr>\n              <th>\n                Field Name\n              </th>\n              <th>\n                Value Type\n              </th>\n              <th>\n                Meaning\n              </th>\n            </tr>\n            <tr>\n              <td>\n                [[Key]]\n              </td>\n              <td>\n                a String\n              </td>\n              <td>\n                The attribute key\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[Value]]\n              </td>\n              <td>\n                a String\n              </td>\n              <td>\n                The attribute value\n              </td>\n            </tr>\n          </table>\n        </emu-table>\n\n        ","2.1.3.1":"<dl class=\"header\">\n            <dt>description</dt>\n            <dd></dd>\n          </dl>\n\n          <emu-alg><ol><li>If _left_.[[Specifier]] is not _right_.[[Specifier]], return *false*.</li><li>Let _leftAttrs_ be _left_.[[Attributes]].</li><li>Let _rightAttrs_ be _right_.[[Attributes]].</li><li>Let _leftAttrsCount_ be the number of elements in _leftAttrs_.</li><li>Let _rightAttrsCount_ be the number of elements in _rightAttrs_.</li><li>If _leftAttrsCount_ ≠ _rightAttrsCount_, return *false*.</li><li>For each ImportAttribute Record _l_ of _leftAttrs_, do<ol><li>If _rightAttrs_ does not contain an ImportAttribute Record _r_ such that _l_.[[Key]] is _r_.[[Key]] and _l_.[[Value]] is _r_.[[Value]], return *false*.</li></ol></li><li>Return *true*.</li></ol></emu-alg>\n        ","2.1.4":"<dl class=\"header\">\n        </dl>\n        <pre class=\"emu-grammar\">Module : [empty]</pre>\n        <emu-alg><ol><li>Return a new empty List.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ModuleItemList : ModuleItem</pre>\n        <emu-alg><ol><li>Return the ModuleRequests of |ModuleItem|.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ModuleItemList : ModuleItemList ModuleItem</pre>\n        <emu-alg><ol><li>Let _requests_ be the ModuleRequests of |ModuleItemList|.</li><li>Let _additionalRequests_ be the ModuleRequests of |ModuleItem|.</li><li>For each ModuleRequest Record _mr_ of _additionalRequests_, do<ol><li>If _requests_ does not contain a ModuleRequest Record _mr2_ such that ModuleRequestsEqual(_mr_, _mr2_) is *true*, then<ol><li>Append _mr_ to _requests_.</li></ol></li></ol></li><li>Return _requests_.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ModuleItem : StatementListItem</pre>\n        <emu-alg><ol><li>Return a new empty List.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ImportDeclaration : `import` ImportClause FromClause `;`</pre>\n        <emu-alg><ol><li>Let _specifier_ be the SV of |FromClause|.</li><li>Return a List whose sole element is the ModuleRequest Record { [[Specifier]]: _specifier_, [[Attributes]]: « » }.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ImportDeclaration : `import` ImportClause FromClause WithClause `;`</pre>\n        <emu-alg><ol><li>Let _specifier_ be the SV of |FromClause|.</li><li>Let _attributes_ be WithClauseToAttributes of |WithClause|.</li><li>Return a List whose sole element is the ModuleRequest Record { [[Specifier]]: _specifier_, [[Attributes]]: _attributes_ }.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ImportDeclaration : `import` ModuleSpecifier `;`</pre>\n        <emu-alg><ol><li>Let _specifier_ be the SV of |ModuleSpecifier|.</li><li>Return a List whose sole element is the ModuleRequest Record { [[Specifier]]: _specifier_, [[Attributes]]: « » }.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ImportDeclaration : `import` ModuleSpecifier WithClause `;`</pre>\n        <emu-alg><ol><li>Let _specifier_ be the SV of |ModuleSpecifier|.</li><li>Let _attributes_ be WithClauseToAttributes of |WithClause|.</li><li>Return a List whose sole element is the ModuleRequest Record { [[Specifier]]: _specifier_, [[Attributes]]: _attributes_ }.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration : `export` ExportFromClause FromClause `;`</pre>\n        <emu-alg><ol><li>Let _specifier_ be the SV of |FromClause|.</li><li>Return a List whose sole element is the ModuleRequest Record { [[Specifier]]: _specifier_, [[Attributes]]: « » }.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration : `export` ExportFromClause FromClause WithClause `;`</pre>\n        <emu-alg><ol><li>Let _specifier_ be the SV of |FromClause|.</li><li>Let _attributes_ be WithClauseToAttributes of |WithClause|.</li><li>Return a List whose sole element is the ModuleRequest Record { [[Specifier]]: _specifier_, [[Attributes]]: _attributes_ }.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration :\n  `export` NamedExports `;`\n  `export` VariableStatement\n  `export` Declaration\n  `export` `default` HoistableDeclaration\n  `export` `default` ClassDeclaration\n  `export` `default` AssignmentExpression `;`</pre>\n        <emu-alg><ol><li>Return a new empty List.</li></ol></emu-alg>\n      ","2.1.5":"<p>A <dfn variants=\"Module Records\">Module Record</dfn> encapsulates structural information about the imports and exports of a single module. This information is used to link the imports and exports of sets of connected modules. A Module Record includes four fields that are only used when evaluating a module.</p>\n        <p>For specification purposes Module Record values are values of the Record specification type and can be thought of as existing in a simple object-oriented hierarchy where Module Record is an abstract class with both abstract and concrete subclasses. This specification defines the abstract subclass named Cyclic Module Record and its concrete subclass named Source Text Module Record. Other specifications and implementations may define additional Module Record subclasses corresponding to alternative module definition facilities that they defined.</p>\n        <p>Module Record defines the fields listed in table-module-record-fields. All Module Definition subclasses include at least those fields. Module Record also defines the abstract method list in table-abstract-methods-of-module-records. All Module definition subclasses must provide concrete implementations of these abstract methods.</p>\n        <emu-table id=\"table-module-record-fields\" caption=\"Module Record Fields\" oldids=\"table-36\">\n          <table>\n            <thead>\n              <tr>\n                <th>\n                  Field Name\n                </th>\n                <th>\n                  Value Type\n                </th>\n                <th>\n                  Meaning\n                </th>\n              </tr>\n            </thead>\n            <tr>\n              <td>\n                [[Realm]]\n              </td>\n              <td>\n                a Realm Record\n              </td>\n              <td>\n                The Realm within which this module was created.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[Environment]]\n              </td>\n              <td>\n                a Module Environment Record or ~empty~\n              </td>\n              <td>\n                The Environment Record containing the top level bindings for this module. This field is set when the module is linked.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[Namespace]]\n              </td>\n              <td>\n                an Object or ~empty~\n              </td>\n              <td>\n                The Module Namespace Object (28.3) if one has been created for this module.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[HostDefined]]\n              </td>\n              <td>\n                anything (default value is *undefined*)\n              </td>\n              <td>\n                Field reserved for use by host environments that need to associate additional information with a module.\n              </td>\n            </tr>\n          </table>\n        </emu-table>\n        <emu-table id=\"table-abstract-methods-of-module-records\" type=\"abstract methods\" of=\"Module Records\" oldids=\"table-37\">\n          <table>\n            <thead>\n              <tr>\n                <th>\n                  Method\n                </th>\n                <th>\n                  Purpose\n                </th>\n                <th>\n                  Definitions\n                </th>\n              </tr>\n            </thead>\n            <tr id=\"abstract-loadrequestedmodules\">\n              <td>\n                LoadRequestedModules (\n                  optional _hostDefined_: anything,\n                ): a Promise\n              </td>\n              <td>\n                <p>It prepares the module for linking by recursively loading all its dependencies.</p>\n              </td>\n              <td>\n                Within this specification it has definitions in the following types; hosts may provide additional types with their own definitions:\n                <emu-concrete-method-dfns for=\"LoadRequestedModules\"></emu-concrete-method-dfns>\n              </td>\n            </tr>\n            <tr id=\"abstract-getexportednames\">\n              <td>\n                GetExportedNames (\n                  optional _exportStarSet_: a List of Source Text Module Records,\n                ): a List of Strings\n              </td>\n              <td>\n                <p>It returns a list of all names that are either directly or indirectly exported from this module.</p>\n                <p>LoadRequestedModules must have completed successfully prior to invoking this method.</p>\n              </td>\n              <td>\n                Within this specification it has definitions in the following types; hosts may provide additional types with their own definitions:\n                <emu-concrete-method-dfns for=\"GetExportedNames\"></emu-concrete-method-dfns>\n              </td>\n            </tr>\n            <tr id=\"abstract-resolveexport\">\n              <td>\n                ResolveExport (\n                  _exportName_: a String,\n                  optional _resolveSet_: a List of Records with fields [[Module]] (a Module Record) and [[ExportName]] (a String),\n                ): a ResolvedBinding Record, *null*, or ~ambiguous~\n              </td>\n              <td>\n                <p>It returns the binding of a name exported by this module. Bindings are represented by a <dfn id=\"resolvedbinding-record\" variants=\"ResolvedBinding Records\">ResolvedBinding Record</dfn>, of the form { [[Module]]: Module Record, [[BindingName]]: String | ~namespace~ }. If the export is a Module Namespace Object without a direct binding in any module, [[BindingName]] will be set to ~namespace~. It returns *null* if the name cannot be resolved, or ~ambiguous~ if multiple bindings were found.</p>\n                <p>Each time this operation is called with a specific _exportName_, _resolveSet_ pair as arguments it must return the same result.</p>\n                <p>LoadRequestedModules must have completed successfully prior to invoking this method.</p>\n              </td>\n              <td>\n                Within this specification it has definitions in the following types; hosts may provide additional types with their own definitions:\n                <emu-concrete-method-dfns for=\"ResolveExport\"></emu-concrete-method-dfns>\n              </td>\n            </tr>\n            <tr id=\"abstract-link\">\n              <td>Link ( ): either a normal completion containing ~unused~ or a throw completion</td>\n              <td>\n                <p>It prepares the module for evaluation by transitively resolving all module dependencies and creating a Module Environment Record.</p>\n                <p>LoadRequestedModules must have completed successfully prior to invoking this method.</p>\n              </td>\n              <td>\n                Within this specification it has definitions in the following types; hosts may provide additional types with their own definitions:\n                <emu-concrete-method-dfns for=\"Link\"></emu-concrete-method-dfns>\n              </td>\n            </tr>\n            <tr id=\"abstract-evaluate\">\n              <td>Evaluate ( ): a Promise</td>\n              <td>\n                <p>It returns a promise for the evaluation of this module and its dependencies, resolving on successful evaluation or if it has already been evaluated successfully, and rejecting for an evaluation error or if it has already been evaluated unsuccessfully. If the promise is rejected, hosts are expected to handle the promise rejection and rethrow the evaluation error. Unless this module is a Cyclic Module Record, the returned promise must be already settled.</p>\n                <p>Link must have completed successfully prior to invoking this method.</p>\n              </td>\n              <td>\n                Within this specification it has definitions in the following types; hosts may provide additional types with their own definitions:\n                <emu-concrete-method-dfns for=\"Evaluate\"></emu-concrete-method-dfns>\n              </td>\n            </tr>\n          </table>\n        </emu-table>\n\n        ","2.1.5.1":"<dl class=\"header\">\n            <dt>description</dt>\n            <dd>It synchronously evaluates _module_, provided that the caller guarantees that _module_'s evaluation will return an already settled promise.</dd>\n          </dl>\n\n          <emu-alg><ol><li>Assert: _module_ is not a Cyclic Module Record.</li><li>Let _promise_ be _module_.Evaluate().</li><li>Assert: _promise_.[[PromiseState]] is either ~fulfilled~ or ~rejected~.</li><li>If _promise_.[[PromiseState]] is ~rejected~, then<ol><li>If _promise_.[[PromiseIsHandled]] is *false*, perform HostPromiseRejectionTracker(_promise_, *\"handle\"*).</li><li>Set _promise_.[[PromiseIsHandled]] to *true*.</li><li>Throw _promise_.[[PromiseResult]].</li></ol></li><li>Return ~unused~.</li></ol></emu-alg>\n        ","2.1.6":"<p>A <dfn id=\"cyclic-module-record\" variants=\"Cyclic Module Records\">Cyclic Module Record</dfn> is used to represent information about a module that can participate in dependency cycles with other modules that are subclasses of the Cyclic Module Record type. Module Records that are not subclasses of the Cyclic Module Record type must not participate in dependency cycles with Source Text Module Records.</p>\n        <p>In addition to the fields defined in table-module-record-fields Cyclic Module Records have the additional fields listed in table-cyclic-module-fields</p>\n        <emu-table id=\"table-cyclic-module-fields\" caption=\"Additional Fields of Cyclic Module Records\">\n          <table>\n            <thead>\n              <tr>\n                <th>\n                  Field Name\n                </th>\n                <th>\n                  Value Type\n                </th>\n                <th>\n                  Meaning\n                </th>\n              </tr>\n            </thead>\n            <tr>\n              <td>\n                [[Status]]\n              </td>\n              <td>\n                ~new~, ~unlinked~, ~linking~, ~linked~, ~evaluating~, ~evaluating-async~, or ~evaluated~\n              </td>\n              <td>\n                Initially ~new~. Transitions to ~unlinked~, ~linking~, ~linked~, ~evaluating~, possibly ~evaluating-async~, ~evaluated~ (in that order) as the module progresses throughout its lifecycle. ~evaluating-async~ indicates this module is queued to execute on completion of its asynchronous dependencies or it is a module whose [[HasTLA]] field is *true* that has been executed and is pending top-level completion.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[EvaluationError]]\n              </td>\n              <td>\n                a throw completion or ~empty~\n              </td>\n              <td>\n                A throw completion representing the exception that occurred during evaluation. ~empty~ if no exception occurred or if [[Status]] is not ~evaluated~.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[DFSAncestorIndex]]\n              </td>\n              <td>\n                an integer or ~empty~\n              </td>\n              <td>\n                Auxiliary field used during Link and Evaluate only. If [[Status]] is either ~linking~ or ~evaluating~, this is either the module's depth-first traversal index or that of an \"earlier\" module in the same strongly connected component.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[RequestedModules]]\n              </td>\n              <td>\n                a List of ModuleRequest Records\n              </td>\n              <td>\n                A List of the ModuleRequest Records associated with the imports in this module. The List is in source text occurrence order of the imports.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[LoadedModules]]\n              </td>\n              <td>\n                a List of LoadedModuleRequest Records\n              </td>\n              <td>\n                A map from the specifier strings used by the module represented by this record to request the importation of a module with the relative import attributes to the resolved Module Record. The list does not contain two different Records _r1_ and _r2_ such that ModuleRequestsEqual(_r1_, _r2_) is *true*.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[CycleRoot]]\n              </td>\n              <td>\n                a Cyclic Module Record or ~empty~\n              </td>\n              <td>\n                The first visited module of the cycle, the root DFS ancestor of the strongly connected component. For a module not in a cycle, this would be the module itself. Once Evaluate has completed, a module's [[DFSAncestorIndex]] is the depth-first traversal index of its [[CycleRoot]].\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[HasTLA]]\n              </td>\n              <td>\n                a Boolean\n              </td>\n              <td>\n                Whether this module is individually asynchronous (for example, if it's a Source Text Module Record containing a top-level await). Having an asynchronous dependency does not mean this field is *true*. This field must not change after the module is parsed.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[AsyncEvaluationOrder]]\n              </td>\n              <td>\n                ~unset~, an integer, or ~done~\n              </td>\n              <td>\n                This field is initially set to ~unset~, and remains ~unset~ for fully synchronous modules. For modules that are either themselves asynchronous or have an asynchronous dependency, it is set to an integer that determines the order in which execution of pending modules is queued by 16.2.1.6.1.3.4. Once the pending module is successfully executed, the field is set to ~done~.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[TopLevelCapability]]\n              </td>\n              <td>\n                a PromiseCapability Record or ~empty~\n              </td>\n              <td>\n                If this module is the [[CycleRoot]] of some cycle, and Evaluate() was called on some module in that cycle, this field contains the PromiseCapability Record for that entire evaluation. It is used to settle the Promise object that is returned from the Evaluate() abstract method. This field will be ~empty~ for any dependencies of that module, unless a top-level Evaluate() has been initiated for some of those dependencies.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[AsyncParentModules]]\n              </td>\n              <td>\n                a List of Cyclic Module Records\n              </td>\n              <td>\n                If this module or a dependency has [[HasTLA]] *true*, and execution is in progress, this tracks the parent importers of this module for the top-level execution job. These parent modules will not start executing before this module has successfully completed execution.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[PendingAsyncDependencies]]\n              </td>\n              <td>\n                an integer or ~empty~\n              </td>\n              <td>\n                If this module has any asynchronous dependencies, this tracks the number of asynchronous dependency modules remaining to execute for this module. A module with asynchronous dependencies will be executed when this field reaches 0 and there are no execution errors.\n              </td>\n            </tr>\n          </table>\n        </emu-table>\n        <p>In addition to the methods defined in table-abstract-methods-of-module-records Cyclic Module Records have the additional methods listed in table-cyclic-module-methods:</p>\n        <emu-table id=\"table-cyclic-module-methods\" type=\"abstract methods\" of=\"Cyclic Module Records\" caption=\"Additional Abstract Methods of Cyclic Module Records\">\n          <table>\n            <thead>\n              <tr>\n                <th>\n                  Method\n                </th>\n                <th>\n                  Purpose\n                </th>\n                <th>\n                  Definitions\n                </th>\n              </tr>\n            </thead>\n            <tr id=\"abstract-initializeenvironment\">\n              <td>InitializeEnvironment ( ): either a normal completion containing ~unused~ or a throw completion</td>\n              <td>\n                It initializes the Environment Record of the module, including resolving all imported bindings, and creates the module's execution context.\n              </td>\n              <td>\n                Within this specification it has definitions in the following types; hosts may provide additional types with their own definitions:\n                <emu-concrete-method-dfns for=\"InitializeEnvironment\"></emu-concrete-method-dfns>\n              </td>\n            </tr>\n            <tr id=\"abstract-executemodule\">\n              <td>\n                ExecuteModule (\n                  optional _capability_: a PromiseCapability Record,\n                ): either a normal completion containing ~unused~ or a throw completion\n              </td>\n              <td>\n                It evaluates the module's code within its execution context. If this module has *true* in [[HasTLA]], then a PromiseCapability Record is passed as an argument, and the method is expected to resolve or reject the given capability. In this case, the method must not throw an exception, but instead reject the PromiseCapability Record if necessary.\n              </td>\n              <td>\n                Within this specification it has definitions in the following types; hosts may provide additional types with their own definitions:\n                <emu-concrete-method-dfns for=\"ExecuteModule\"></emu-concrete-method-dfns>\n              </td>\n            </tr>\n          </table>\n        </emu-table>\n\n        <p>A <dfn id=\"graphloadingstate-record\" variants=\"GraphLoadingState Records\">GraphLoadingState Record</dfn> is a Record that contains information about the loading process of a module graph. It's used to continue loading after a call to HostLoadImportedModule. Each GraphLoadingState Record has the fields defined in table-graphloadingstate-record-fields:</p>\n        <emu-table id=\"table-graphloadingstate-record-fields\" caption=\"GraphLoadingState Record Fields\">\n          <table>\n            <thead>\n              <tr>\n                <th>\n                  Field Name\n                </th>\n                <th>\n                  Value Type\n                </th>\n                <th>\n                  Meaning\n                </th>\n              </tr>\n            </thead>\n            <tr>\n              <td>\n                [[PromiseCapability]]\n              </td>\n              <td>\n                a PromiseCapability Record\n              </td>\n              <td>\n                The promise to resolve when the loading process finishes.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[IsLoading]]\n              </td>\n              <td>\n                a Boolean\n              </td>\n              <td>\n                It is true if the loading process has not finished yet, neither successfully nor with an error.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[PendingModulesCount]]\n              </td>\n              <td>\n                a non-negative integer\n              </td>\n              <td>\n                It tracks the number of pending HostLoadImportedModule calls.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[Visited]]\n              </td>\n              <td>\n                a List of Cyclic Module Records\n              </td>\n              <td>\n                It is a list of the Cyclic Module Records that have been already loaded by the current loading process, to avoid infinite loops with circular dependencies.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[HostDefined]]\n              </td>\n              <td>\n                anything (default value is ~empty~)\n              </td>\n              <td>\n                It contains host-defined data to pass from the LoadRequestedModules caller to HostLoadImportedModule.\n              </td>\n            </tr>\n          </table>\n        </emu-table>\n\n        ","2.1.6.1":"<p>The following are the concrete methods for Cyclic Module Record that implement the corresponding Module Record abstract methods defined in table-abstract-methods-of-module-records.</p>\n\n          ","2.1.6.1.1":"<dl class=\"header\">\n              <dt>for</dt>\n              <dd>a Cyclic Module Record _module_</dd>\n\n              <dt>description</dt>\n              <dd>It populates the [[LoadedModules]] of all the Module Records in the dependency graph of _module_ (most of the work is done by the auxiliary function InnerModuleLoading). It takes an optional _hostDefined_ parameter that is passed to the HostLoadImportedModule hook.</dd>\n            </dl>\n\n            <emu-alg><ol><li>If _hostDefined_ is not present, set _hostDefined_ to ~empty~.</li><li>Let _pc_ be ! NewPromiseCapability(%Promise%).</li><li>Let _state_ be the GraphLoadingState Record { [[IsLoading]]: *true*, [[PendingModulesCount]]: 1, [[Visited]]: « », [[PromiseCapability]]: _pc_, [[HostDefined]]: _hostDefined_ }.</li><li>Perform InnerModuleLoading(_state_, _module_).</li><li>Return _pc_.[[Promise]].</li></ol></emu-alg>\n\n            <emu-note>\n              The _hostDefined_ parameter can be used to pass additional information necessary to fetch the imported modules. It is used, for example, by HTML to set the correct fetch destination for <code>&lt;link rel=\"preload\" as=\"...\"&gt;</code> tags.\n              <code>import()</code> expressions never set the _hostDefined_ parameter.\n            </emu-note>\n\n            ","2.1.6.1.1.1":"<dl class=\"header\">\n                <dt>description</dt>\n                <dd>It is used by LoadRequestedModules to recursively perform the actual loading process for _module_'s dependency graph.</dd>\n              </dl>\n\n              <emu-alg><ol><li>Assert: _state_.[[IsLoading]] is *true*.</li><li>If _module_ is a Cyclic Module Record, _module_.[[Status]] is ~new~, and _state_.[[Visited]] does not contain _module_, then<ol><li>Append _module_ to _state_.[[Visited]].</li><li>Let _requestedModulesCount_ be the number of elements in _module_.[[RequestedModules]].</li><li>Set _state_.[[PendingModulesCount]] to _state_.[[PendingModulesCount]] + _requestedModulesCount_.</li><li>For each ModuleRequest Record _request_ of _module_.[[RequestedModules]], do<ol><li>If AllImportAttributesSupported(_request_.[[Attributes]]) is *false*, then<ol><li>Let _error_ be ThrowCompletion(a newly created *SyntaxError* object).</li><li>Perform ContinueModuleLoading(_state_, _error_).</li></ol></li><li>Else if _module_.[[LoadedModules]] contains a LoadedModuleRequest Record _record_ such that ModuleRequestsEqual(_record_, _request_) is *true*, then<ol><li>Perform InnerModuleLoading(_state_, _record_.[[Module]]).</li></ol></li><li>Else,<ol><li>Perform HostLoadImportedModule(_module_, _request_, _state_.[[HostDefined]], _state_).</li><li>NOTE: HostLoadImportedModule will call FinishLoadingImportedModule, which re-enters the graph loading process through ContinueModuleLoading.</li></ol></li><li>If _state_.[[IsLoading]] is *false*, return ~unused~.</li></ol></li></ol></li><li>Assert: _state_.[[PendingModulesCount]] ≥ 1.</li><li>Set _state_.[[PendingModulesCount]] to _state_.[[PendingModulesCount]] - 1.</li><li>If _state_.[[PendingModulesCount]] = 0, then<ol><li>Set _state_.[[IsLoading]] to *false*.</li><li>For each Cyclic Module Record _loaded_ of _state_.[[Visited]], do<ol><li>If _loaded_.[[Status]] is ~new~, set _loaded_.[[Status]] to ~unlinked~.</li></ol></li><li>Perform ! Call(_state_.[[PromiseCapability]].[[Resolve]], *undefined*, « *undefined* »).</li></ol></li><li>Return ~unused~.</li></ol></emu-alg>\n            ","2.1.6.1.1.2":"<dl class=\"header\">\n                <dt>description</dt>\n                <dd>It is used to re-enter the loading process after a call to HostLoadImportedModule.</dd>\n              </dl>\n\n              <emu-alg><ol><li>If _state_.[[IsLoading]] is *false*, return ~unused~.</li><li>If _moduleCompletion_ is a normal completion, then<ol><li>Perform InnerModuleLoading(_state_, _moduleCompletion_.[[Value]]).</li></ol></li><li>Else,<ol><li>Set _state_.[[IsLoading]] to *false*.</li><li>Perform ! Call(_state_.[[PromiseCapability]].[[Reject]], *undefined*, « _moduleCompletion_.[[Value]] »).</li></ol></li><li>Return ~unused~.</li></ol></emu-alg>\n            ","2.1.6.1.2":"<dl class=\"header\">\n              <dt>for</dt>\n              <dd>a Cyclic Module Record _module_</dd>\n\n              <dt>description</dt>\n              <dd>On success, Link transitions this module's [[Status]] from ~unlinked~ to ~linked~. On failure, an exception is thrown and this module's [[Status]] remains ~unlinked~. (Most of the work is done by the auxiliary function InnerModuleLinking.)</dd>\n            </dl>\n\n            <emu-alg><ol><li>Assert: _module_.[[Status]] is one of ~unlinked~, ~linked~, ~evaluating-async~, or ~evaluated~.</li><li>Let _stack_ be a new empty List.</li><li>Let _result_ be Completion(InnerModuleLinking(_module_, _stack_, 0)).</li><li>If _result_ is an abrupt completion, then<ol><li>For each Cyclic Module Record _m_ of _stack_, do<ol><li>Assert: _m_.[[Status]] is ~linking~.</li><li>Set _m_.[[Status]] to ~unlinked~.</li></ol></li><li>Assert: _module_.[[Status]] is ~unlinked~.</li><li>Return ? _result_.</li></ol></li><li>Assert: _module_.[[Status]] is one of ~linked~, ~evaluating-async~, or ~evaluated~.</li><li>Assert: _stack_ is empty.</li><li>Return ~unused~.</li></ol></emu-alg>\n\n            ","2.1.6.1.2.1":"<dl class=\"header\">\n                <dt>description</dt>\n                <dd>It is used by Link to perform the actual linking process for _module_, as well as recursively on all other modules in the dependency graph. The _stack_ and _index_ parameters, as well as a module's [[DFSAncestorIndex]] field, keep track of the depth-first search (DFS) traversal. In particular, [[DFSAncestorIndex]] is used to discover strongly connected components (SCCs), such that all modules in an SCC transition to ~linked~ together.</dd>\n              </dl>\n\n              <emu-alg><ol><li>If _module_ is not a Cyclic Module Record, then<ol><li>Perform ? _module_.Link().</li><li>Return _index_.</li></ol></li><li>If _module_.[[Status]] is one of ~linking~, ~linked~, ~evaluating-async~, or ~evaluated~, then<ol><li>Return _index_.</li></ol></li><li>Assert: _module_.[[Status]] is ~unlinked~.</li><li>Set _module_.[[Status]] to ~linking~.</li><li>Let _moduleIndex_ be _index_.</li><li>Set _module_.[[DFSAncestorIndex]] to _index_.</li><li>Set _index_ to _index_ + 1.</li><li>Append _module_ to _stack_.</li><li>For each ModuleRequest Record _request_ of _module_.[[RequestedModules]], do<ol><li>Let _requiredModule_ be GetImportedModule(_module_, _request_).</li><li>Set _index_ to ? InnerModuleLinking(_requiredModule_, _stack_, _index_).</li><li>If _requiredModule_ is a Cyclic Module Record, then<ol><li>Assert: _requiredModule_.[[Status]] is one of ~linking~, ~linked~, ~evaluating-async~, or ~evaluated~.</li><li>Assert: _requiredModule_.[[Status]] is ~linking~ if and only if _stack_ contains _requiredModule_.</li><li>If _requiredModule_.[[Status]] is ~linking~, then<ol><li>Set _module_.[[DFSAncestorIndex]] to min(_module_.[[DFSAncestorIndex]], _requiredModule_.[[DFSAncestorIndex]]).</li></ol></li></ol></li></ol></li><li>Perform ? _module_.InitializeEnvironment().</li><li>Assert: _module_ occurs exactly once in _stack_.</li><li>Assert: _module_.[[DFSAncestorIndex]] ≤ _moduleIndex_.</li><li>If _module_.[[DFSAncestorIndex]] = _moduleIndex_, then<ol><li>Let _done_ be *false*.</li><li>Repeat, while _done_ is *false*,<ol><li>Let _requiredModule_ be the last element of _stack_.</li><li>Remove the last element of _stack_.</li><li>Assert: _requiredModule_ is a Cyclic Module Record.</li><li>Set _requiredModule_.[[Status]] to ~linked~.</li><li>If _requiredModule_ and _module_ are the same Module Record, set _done_ to *true*.</li></ol></li></ol></li><li>Return _index_.</li></ol></emu-alg>\n            ","2.1.6.1.3":"<dl class=\"header\">\n              <dt>for</dt>\n              <dd>a Cyclic Module Record _module_</dd>\n\n              <dt>description</dt>\n              <dd>Evaluate transitions this module's [[Status]] from ~linked~ to either ~evaluating-async~ or ~evaluated~. The first time it is called on a module in a given strongly connected component, Evaluate creates and returns a Promise which resolves when the module has finished evaluating. This Promise is stored in the [[TopLevelCapability]] field of the [[CycleRoot]] for the component. Future invocations of Evaluate on any module in the component return the same Promise. (Most of the work is done by the auxiliary function InnerModuleEvaluation.)</dd>\n            </dl>\n\n            <emu-alg><ol><li>Assert: This call to Evaluate is not happening at the same time as another call to Evaluate within the surrounding agent.</li><li>Assert: _module_.[[Status]] is one of ~linked~, ~evaluating-async~, or ~evaluated~.</li><li>If _module_.[[Status]] is either ~evaluating-async~ or ~evaluated~, then<ol><li>If _module_.[[CycleRoot]] is not ~empty~, then<ol><li>Set _module_ to _module_.[[CycleRoot]].</li></ol></li><li>Else,<ol><li>Assert: _module_.[[Status]] is ~evaluated~ and _module_.[[EvaluationError]] is a throw completion.</li></ol></li></ol></li><li>If _module_.[[TopLevelCapability]] is not ~empty~, then<ol><li>Return _module_.[[TopLevelCapability]].[[Promise]].</li></ol></li><li>Let _stack_ be a new empty List.</li><li>Let _capability_ be ! NewPromiseCapability(%Promise%).</li><li>Set _module_.[[TopLevelCapability]] to _capability_.</li><li>Let _result_ be Completion(InnerModuleEvaluation(_module_, _stack_, 0)).</li><li>If _result_ is an abrupt completion, then<ol><li>For each Cyclic Module Record _m_ of _stack_, do<ol><li>Assert: _m_.[[Status]] is ~evaluating~.</li><li>Set _m_.[[Status]] to ~evaluated~.</li><li>Set _m_.[[EvaluationError]] to _result_.</li></ol></li><li>Assert: _module_.[[Status]] is ~evaluated~.</li><li>Assert: _module_.[[EvaluationError]] and _result_ are the same Completion Record.</li><li>Perform ! Call(_capability_.[[Reject]], *undefined*, « _result_.[[Value]] »).</li></ol></li><li>Else,<ol><li>Assert: _module_.[[Status]] is either ~evaluating-async~ or ~evaluated~.</li><li>Assert: _module_.[[EvaluationError]] is ~empty~.</li><li>If _module_.[[Status]] is ~evaluated~, then<ol><li>Assert: _module_.[[AsyncEvaluationOrder]] is either ~unset~ or ~done~.</li><li>NOTE: _module_.[[AsyncEvaluationOrder]] is ~done~ if and only if _module_ had already been evaluated and that evaluation was asynchronous.</li><li>Perform ! Call(_capability_.[[Resolve]], *undefined*, « *undefined* »).</li></ol></li><li>Assert: _stack_ is empty.</li></ol></li><li>Return _capability_.[[Promise]].</li></ol></emu-alg>\n\n            ","2.1.6.1.3.1":"<dl class=\"header\">\n                <dt>description</dt>\n                <dd>It is used by Evaluate to perform the actual evaluation process for _module_, as well as recursively on all other modules in the dependency graph. The _stack_ and _index_ parameters, as well as _module_'s [[DFSAncestorIndex]] field, are used the same way as in InnerModuleLinking.</dd>\n              </dl>\n\n              <emu-alg><ol><li>If _module_ is not a Cyclic Module Record, then<ol><li>Perform ? EvaluateModuleSync(_module_).</li><li>Return _index_.</li></ol></li><li>If _module_.[[Status]] is either ~evaluating-async~ or ~evaluated~, then<ol><li>If _module_.[[EvaluationError]] is ~empty~, return _index_.</li><li>Return ? _module_.[[EvaluationError]].</li></ol></li><li>If _module_.[[Status]] is ~evaluating~, return _index_.</li><li>Assert: _module_.[[Status]] is ~linked~.</li><li>Set _module_.[[Status]] to ~evaluating~.</li><li>Let _moduleIndex_ be _index_.</li><li>Set _module_.[[DFSAncestorIndex]] to _index_.</li><li>Set _module_.[[PendingAsyncDependencies]] to 0.</li><li>Set _index_ to _index_ + 1.</li><li>Append _module_ to _stack_.</li><li>For each ModuleRequest Record _request_ of _module_.[[RequestedModules]], do<ol><li>Let _requiredModule_ be GetImportedModule(_module_, _request_).</li><li>Set _index_ to ? InnerModuleEvaluation(_requiredModule_, _stack_, _index_).</li><li>If _requiredModule_ is a Cyclic Module Record, then<ol><li>Assert: _requiredModule_.[[Status]] is one of ~evaluating~, ~evaluating-async~, or ~evaluated~.</li><li>Assert: _requiredModule_.[[Status]] is ~evaluating~ if and only if _stack_ contains _requiredModule_.</li><li>If _requiredModule_.[[Status]] is ~evaluating~, then<ol><li>Set _module_.[[DFSAncestorIndex]] to min(_module_.[[DFSAncestorIndex]], _requiredModule_.[[DFSAncestorIndex]]).</li></ol></li><li>Else,<ol><li>Set _requiredModule_ to _requiredModule_.[[CycleRoot]].</li><li>Assert: _requiredModule_.[[Status]] is either ~evaluating-async~ or ~evaluated~.</li><li>If _requiredModule_.[[EvaluationError]] is not ~empty~, return ? _requiredModule_.[[EvaluationError]].</li></ol></li><li>If _requiredModule_.[[AsyncEvaluationOrder]] is an integer, then<ol><li>Set _module_.[[PendingAsyncDependencies]] to _module_.[[PendingAsyncDependencies]] + 1.</li><li>Append _module_ to _requiredModule_.[[AsyncParentModules]].</li></ol></li></ol></li></ol></li><li>If _module_.[[PendingAsyncDependencies]] > 0 or _module_.[[HasTLA]] is *true*, then<ol><li>Assert: _module_.[[AsyncEvaluationOrder]] is ~unset~.</li><li>Set _module_.[[AsyncEvaluationOrder]] to IncrementModuleAsyncEvaluationCount().</li><li>If _module_.[[PendingAsyncDependencies]] = 0, perform ExecuteAsyncModule(_module_).</li></ol></li><li>Else,<ol><li>Perform ? <emu-meta effects=\"user-code\">_module_.ExecuteModule()</emu-meta>.</li></ol></li><li>Assert: _module_ occurs exactly once in _stack_.</li><li>Assert: _module_.[[DFSAncestorIndex]] ≤ _moduleIndex_.</li><li>If _module_.[[DFSAncestorIndex]] = _moduleIndex_, then<ol><li>Let _done_ be *false*.</li><li>Repeat, while _done_ is *false*,<ol><li>Let _requiredModule_ be the last element of _stack_.</li><li>Remove the last element of _stack_.</li><li>Assert: _requiredModule_ is a Cyclic Module Record.</li><li>Assert: _requiredModule_.[[AsyncEvaluationOrder]] is either an integer or ~unset~.</li><li>If _requiredModule_.[[AsyncEvaluationOrder]] is ~unset~, set _requiredModule_.[[Status]] to ~evaluated~.</li><li>Else, set _requiredModule_.[[Status]] to ~evaluating-async~.</li><li>If _requiredModule_ and _module_ are the same Module Record, set _done_ to *true*.</li><li>Set _requiredModule_.[[CycleRoot]] to _module_.</li></ol></li></ol></li><li>Return _index_.</li></ol></emu-alg>\n              <emu-note>\n                <p>A module is ~evaluating~ while it is being traversed by InnerModuleEvaluation. A module is ~evaluated~ on execution completion or ~evaluating-async~ during execution if its [[HasTLA]] field is *true* or if it has asynchronous dependencies.</p>\n              </emu-note>\n              <emu-note>\n                <p>Any modules depending on a module of an asynchronous cycle when that cycle is not ~evaluating~ will instead depend on the execution of the root of the cycle via [[CycleRoot]]. This ensures that the cycle state can be treated as a single strongly connected component through its root module state.</p>\n              </emu-note>\n            ","2.1.6.1.3.2":"<dl class=\"header\">\n              </dl>\n\n              <emu-alg><ol><li>Assert: _module_.[[Status]] is either ~evaluating~ or ~evaluating-async~.</li><li>Assert: _module_.[[HasTLA]] is *true*.</li><li>Let _capability_ be ! NewPromiseCapability(%Promise%).</li><li>Let _fulfilledClosure_ be a new Abstract Closure with no parameters that captures _module_ and performs the following steps when called:<ol><li>Perform AsyncModuleExecutionFulfilled(_module_).</li><li>Return NormalCompletion(*undefined*).</li></ol></li><li>Let _onFulfilled_ be CreateBuiltinFunction(_fulfilledClosure_, 0, *\"\"*, « »).</li><li>Let _rejectedClosure_ be a new Abstract Closure with parameters (_error_) that captures _module_ and performs the following steps when called:<ol><li>Perform AsyncModuleExecutionRejected(_module_, _error_).</li><li>Return NormalCompletion(*undefined*).</li></ol></li><li>Let _onRejected_ be CreateBuiltinFunction(_rejectedClosure_, 0, *\"\"*, « »).</li><li>Perform PerformPromiseThen(_capability_.[[Promise]], _onFulfilled_, _onRejected_).</li><li>Perform ! <emu-meta effects=\"user-code\">_module_.ExecuteModule(_capability_)</emu-meta>.</li><li>Return ~unused~.</li></ol></emu-alg>\n            ","2.1.6.1.3.3":"<dl class=\"header\">\n              </dl>\n              <emu-alg><ol><li>For each Cyclic Module Record _m_ of _module_.[[AsyncParentModules]], do<ol><li>If _execList_ does not contain _m_ and _m_.[[CycleRoot]].[[EvaluationError]] is ~empty~, then<ol><li>Assert: _m_.[[Status]] is ~evaluating-async~.</li><li>Assert: _m_.[[EvaluationError]] is ~empty~.</li><li>Assert: _m_.[[AsyncEvaluationOrder]] is an integer.</li><li>Assert: _m_.[[PendingAsyncDependencies]] > 0.</li><li>Set _m_.[[PendingAsyncDependencies]] to _m_.[[PendingAsyncDependencies]] - 1.</li><li>If _m_.[[PendingAsyncDependencies]] = 0, then<ol><li>Append _m_ to _execList_.</li><li>If _m_.[[HasTLA]] is *false*, perform GatherAvailableAncestors(_m_, _execList_).</li></ol></li></ol></li></ol></li><li>Return ~unused~.</li></ol></emu-alg>\n              <emu-note>\n                <p>When an asynchronous execution for a root _module_ is fulfilled, this function determines the list of modules which are able to synchronously execute together on this completion, populating them in _execList_.</p>\n              </emu-note>\n            ","2.1.6.1.3.4":"<dl class=\"header\">\n              </dl>\n              <emu-alg><ol><li>If _module_.[[Status]] is ~evaluated~, then<ol><li>Assert: _module_.[[EvaluationError]] is not ~empty~.</li><li>Return ~unused~.</li></ol></li><li>Assert: _module_.[[Status]] is ~evaluating-async~.</li><li>Assert: _module_.[[AsyncEvaluationOrder]] is an integer.</li><li>Assert: _module_.[[EvaluationError]] is ~empty~.</li><li>Set _module_.[[AsyncEvaluationOrder]] to ~done~.</li><li>Set _module_.[[Status]] to ~evaluated~.</li><li>If _module_.[[TopLevelCapability]] is not ~empty~, then<ol><li>Assert: _module_.[[CycleRoot]] and _module_ are the same Module Record.</li><li>Perform ! Call(_module_.[[TopLevelCapability]].[[Resolve]], *undefined*, « *undefined* »).</li></ol></li><li>Let _execList_ be a new empty List.</li><li>Perform GatherAvailableAncestors(_module_, _execList_).</li><li>Assert: All elements of _execList_ have their [[AsyncEvaluationOrder]] field set to an integer, [[PendingAsyncDependencies]] field set to 0, and [[EvaluationError]] field set to ~empty~.</li><li>Let _sortedExecList_ be a List whose elements are the elements of _execList_, sorted by their [[AsyncEvaluationOrder]] field in ascending order.</li><li>For each Cyclic Module Record _m_ of _sortedExecList_, do<ol><li>If _m_.[[Status]] is ~evaluated~, then<ol><li>Assert: _m_.[[EvaluationError]] is not ~empty~.</li></ol></li><li>Else if _m_.[[HasTLA]] is *true*, then<ol><li>Perform ExecuteAsyncModule(_m_).</li></ol></li><li>Else,<ol><li>Let _result_ be Completion(<emu-meta effects=\"user-code\">_m_.ExecuteModule()</emu-meta>).</li><li>If _result_ is an abrupt completion, then<ol><li>Perform AsyncModuleExecutionRejected(_m_, _result_.[[Value]]).</li></ol></li><li>Else,<ol><li>Set _m_.[[AsyncEvaluationOrder]] to ~done~.</li><li>Set _m_.[[Status]] to ~evaluated~.</li><li>If _m_.[[TopLevelCapability]] is not ~empty~, then<ol><li>Assert: _m_.[[CycleRoot]] and _m_ are the same Module Record.</li><li>Perform ! Call(_m_.[[TopLevelCapability]].[[Resolve]], *undefined*, « *undefined* »).</li></ol></li></ol></li></ol></li></ol></li><li>Return ~unused~.</li></ol></emu-alg>\n            ","2.1.6.1.3.5":"<dl class=\"header\">\n              </dl>\n              <emu-alg><ol><li>If _module_.[[Status]] is ~evaluated~, then<ol><li>Assert: _module_.[[EvaluationError]] is not ~empty~.</li><li>Return ~unused~.</li></ol></li><li>Assert: _module_.[[Status]] is ~evaluating-async~.</li><li>Assert: _module_.[[AsyncEvaluationOrder]] is an integer.</li><li>Assert: _module_.[[EvaluationError]] is ~empty~.</li><li>Set _module_.[[EvaluationError]] to ThrowCompletion(_error_).</li><li>Set _module_.[[Status]] to ~evaluated~.</li><li>Set _module_.[[AsyncEvaluationOrder]] to ~done~.</li><li>NOTE: _module_.[[AsyncEvaluationOrder]] is set to ~done~ for symmetry with AsyncModuleExecutionFulfilled. In InnerModuleEvaluation, the value of a module's [[AsyncEvaluationOrder]] internal slot is unused when its [[EvaluationError]] internal slot is not ~empty~.</li><li>If _module_.[[TopLevelCapability]] is not ~empty~, then<ol><li>Assert: _module_.[[CycleRoot]] and _module_ are the same Module Record.</li><li>Perform ! Call(_module_.[[TopLevelCapability]].[[Reject]], *undefined*, « _error_ »).</li></ol></li><li>For each Cyclic Module Record _m_ of _module_.[[AsyncParentModules]], do<ol><li>Perform AsyncModuleExecutionRejected(_m_, _error_).</li></ol></li><li>Return ~unused~.</li></ol></emu-alg>\n            ","2.1.6.2":"<p>This non-normative section gives a series of examples of the linking and evaluation of a few common module graphs, with a specific focus on how errors can occur.</p>\n\n          <p>First consider the following simple module graph:</p>\n\n          <emu-figure id=\"figure-module-graph-simple\" caption=\"A simple module graph\">\n            <img alt=\"A module graph in which module A depends on module B, and module B depends on module C\" width=\"60\" height=\"198\" src=\"img/module-graph-simple.svg\">\n          </emu-figure>\n\n          <p>Let's first assume that there are no error conditions. When a host first calls _A_.LoadRequestedModules(), this will complete successfully by assumption, and recursively load the dependencies of _B_ and _C_ as well (respectively, _C_ and none), and then set _A_.[[Status]] = _B_.[[Status]] = _C_.[[Status]] = ~unlinked~. Then, when the host calls _A_.Link(), it will complete successfully (again by assumption) such that _A_.[[Status]] = _B_.[[Status]] = _C_.[[Status]] = ~linked~. These preparatory steps can be performed at any time. Later, when the host is ready to incur any possible side effects of the modules, it can call _A_.Evaluate(), which will complete successfully, returning a Promise resolving to *undefined* (again by assumption), recursively having evaluated first _C_ and then _B_. Each module's [[Status]] at this point will be ~evaluated~.</p>\n\n          <p>Consider then cases involving linking errors, after a successful call to _A_.LoadRequestedModules(). If InnerModuleLinking of _C_ succeeds but, thereafter, fails for _B_, for example because it imports something that _C_ does not provide, then the original _A_.Link() will fail, and both _A_ and _B_'s [[Status]] remain ~unlinked~. _C_'s [[Status]] has become ~linked~, though.</p>\n\n          <p>Finally, consider a case involving evaluation errors after a successful call to Link(). If InnerModuleEvaluation of _C_ succeeds but, thereafter, fails for _B_, for example because _B_ contains code that throws an exception, then the original _A_.Evaluate() will fail, returning a rejected Promise. The resulting exception will be recorded in both _A_ and _B_'s [[EvaluationError]] fields, and their [[Status]] will become ~evaluated~. _C_ will also become ~evaluated~ but, in contrast to _A_ and _B_, will remain without an [[EvaluationError]], as it successfully completed evaluation. Storing the exception ensures that any time a host tries to reuse _A_ or _B_ by calling their Evaluate() method, it will encounter the same exception. (Hosts are not required to reuse Cyclic Module Records; similarly, hosts are not required to expose the exception objects thrown by these methods. However, the specification enables such uses.)</p>\n\n          <p>Now consider a different type of error condition:</p>\n\n          <emu-figure id=\"figure-module-graph-missing\" caption=\"A module graph with an unresolvable module\">\n            <img alt=\"A module graph in which module A depends on a missing (unresolvable) module, represented by ???\" width=\"60\" height=\"121\" src=\"img/module-graph-missing.svg\">\n          </emu-figure>\n\n          <p>In this scenario, module _A_ declares a dependency on some other module, but no Module Record exists for that module, i.e. HostLoadImportedModule calls FinishLoadingImportedModule with an exception when asked for it. This could occur for a variety of reasons, such as the corresponding resource not existing, or the resource existing but ParseModule returning some errors when trying to parse the resulting source text. Hosts can choose to expose the cause of failure via the completion they pass to FinishLoadingImportedModule. In any case, this exception causes a loading failure, which results in _A_'s [[Status]] remaining ~new~.</p>\n\n          <p>The difference here between loading, linking and evaluation errors is due to the following characteristic:</p>\n          <ul>\n            <li>Evaluation must be only performed once, as it can cause side effects; it is thus important to remember whether evaluation has already been performed, even if unsuccessfully. (In the error case, it makes sense to also remember the exception because otherwise subsequent Evaluate() calls would have to synthesize a new one.)</li>\n            <li>Linking, on the other hand, is side-effect-free, and thus even if it fails, it can be retried at a later time with no issues.</li>\n            <li>Loading closely interacts with the host, and it may be desirable for some of them to allow users to retry failed loads (for example, if the failure is caused by temporarily bad network conditions).</li>\n          </ul>\n\n          <p>Now, consider a module graph with a cycle:</p>\n\n          <emu-figure id=\"figure-module-graph-cycle\" caption=\"A cyclic module graph\">\n            <img alt=\"A module graph in which module A depends on module B and C, but module B also depends on module A\" width=\"181\" height=\"121\" src=\"img/module-graph-cycle.svg\">\n          </emu-figure>\n\n          <p>Here we assume that the entry point is module _A_, so that the host proceeds by calling _A_.LoadRequestedModules(), which performs InnerModuleLoading on _A_. This in turn calls InnerModuleLoading on _B_ and _C_. Because of the cycle, this again triggers InnerModuleLoading on _A_, but at this point it is a no-op since _A_'s dependencies loading has already been triggered during this LoadRequestedModules process. When all the modules in the graph have been successfully loaded, their [[Status]] transitions from ~new~ to ~unlinked~ at the same time.</p>\n\n          <p>Then the host proceeds by calling _A_.Link(), which performs InnerModuleLinking on _A_. This in turn calls InnerModuleLinking on _B_. Because of the cycle, this again triggers InnerModuleLinking on _A_, but at this point it is a no-op since _A_.[[Status]] is already ~linking~. _B_.[[Status]] itself remains ~linking~ when control gets back to _A_ and InnerModuleLinking is triggered on _C_. After this returns with _C_.[[Status]] being ~linked~, both _A_ and _B_ transition from ~linking~ to ~linked~ together; this is by design, since they form a strongly connected component. It's possible to transition the status of modules in the same SCC at the same time because during this phase the module graph is traversed with a depth-first search.</p>\n\n          <p>An analogous story occurs for the evaluation phase of a cyclic module graph, in the success case.</p>\n\n          <p>Now consider a case where _A_ has a linking error; for example, it tries to import a binding from _C_ that does not exist. In that case, the above steps still occur, including the early return from the second call to InnerModuleLinking on _A_. However, once we unwind back to the original InnerModuleLinking on _A_, it fails during InitializeEnvironment, namely right after _C_.ResolveExport(). The thrown *SyntaxError* exception propagates up to _A_.Link, which resets all modules that are currently on its _stack_ (these are always exactly the modules that are still ~linking~). Hence both _A_ and _B_ become ~unlinked~. Note that _C_ is left as ~linked~.</p>\n\n          <p>Alternatively, consider a case where _A_ has an evaluation error; for example, its source code throws an exception. In that case, the evaluation-time analogue of the above steps still occurs, including the early return from the second call to InnerModuleEvaluation on _A_. However, once we unwind back to the original InnerModuleEvaluation on _A_, it fails by assumption. The exception thrown propagates up to _A_.Evaluate(), which records the error in all modules that are currently on its _stack_ (i.e., the modules that are still ~evaluating~) as well as via [[AsyncParentModules]], which form a chain for modules which contain or depend on top-level `await` through the whole dependency graph through the AsyncModuleExecutionRejected algorithm. Hence both _A_ and _B_ become ~evaluated~ and the exception is recorded in both _A_ and _B_'s [[EvaluationError]] fields, while _C_ is left as ~evaluated~ with no [[EvaluationError]].</p>\n\n          <p>Lastly, consider a module graph with a cycle, where all modules complete asynchronously:</p>\n          <emu-figure id=\"figure-module-graph-cycle-async\" caption=\"An asynchronous cyclic module graph\">\n            <img alt=\"A module graph in which module A depends on module B and C, module B depends on module D, module C depends on module D and E, and module D depends on module A\" width=\"241\" height=\"211\" src=\"img/module-graph-cycle-async.svg\">\n          </emu-figure>\n          <p>Loading and linking happen as before, and all modules end up with [[Status]] set to ~linked~.</p>\n\n          <p>Calling _A_.Evaluate() calls InnerModuleEvaluation on _A_, _B_, and _D_, which all transition to ~evaluating~. Then InnerModuleEvaluation is called on _A_ again, which is a no-op because it is already ~evaluating~. At this point, _D_.[[PendingAsyncDependencies]] is 0, so ExecuteAsyncModule(_D_) is called and we call _D_.ExecuteModule with a new PromiseCapability tracking the asynchronous execution of _D_. We unwind back to the InnerModuleEvaluation on _B_, setting _B_.[[PendingAsyncDependencies]] to 1 and _B_.[[AsyncEvaluationOrder]] to 1. We unwind back to the original InnerModuleEvaluation on _A_, setting _A_.[[PendingAsyncDependencies]] to 1. In the next iteration of the loop over _A_'s dependencies, we call InnerModuleEvaluation on _C_ and thus on _D_ (again a no-op) and _E_. As _E_ has no dependencies and is not part of a cycle, we call ExecuteAsyncModule(_E_) in the same manner as _D_ and _E_ is immediately removed from the stack. We unwind once more to the InnerModuleEvaluation on _C_, setting _C_.[[AsyncEvaluationOrder]] to 3. Now we finish the loop over _A_'s dependencies, set _A_.[[AsyncEvaluationOrder]] to 4, and remove the entire strongly connected component from the stack, transitioning all of the modules to ~evaluating-async~ at once. At this point, the fields of the modules are as given in table-module-graph-cycle-async-fields-1.</p>\n\n          <emu-table id=\"table-module-graph-cycle-async-fields-1\" caption=\"Module fields after the initial Evaluate() call\">\n            <table>\n              <thead>\n                <tr>\n                  <th class=\"corner-cell\">\n                    <span class=\"column\">Field</span>\n                    <div class=\"slash\">\n                    </div>\n                    <span class=\"row\">Module</span>\n                  </th>\n                  <th>_A_</th>\n                  <th>_B_</th>\n                  <th>_C_</th>\n                  <th>_D_</th>\n                  <th>_E_</th>\n                </tr>\n              </thead>\n              <tr>\n                <th>[[DFSAncestorIndex]]</th>\n                <td>0</td>\n                <td>0</td>\n                <td>0</td>\n                <td>0</td>\n                <td>4</td>\n              </tr>\n              <tr>\n                <th>[[Status]]</th>\n                <td>~evaluating-async~</td>\n                <td>~evaluating-async~</td>\n                <td>~evaluating-async~</td>\n                <td>~evaluating-async~</td>\n                <td>~evaluating-async~</td>\n              </tr>\n              <tr>\n                <th>[[AsyncEvaluationOrder]]</th>\n                <td>4</td>\n                <td>1</td>\n                <td>3</td>\n                <td>0</td>\n                <td>2</td>\n              </tr>\n              <tr>\n                <th>[[AsyncParentModules]]</th>\n                <td>« »</td>\n                <td>« _A_ »</td>\n                <td>« _A_ »</td>\n                <td>« _B_, _C_ »</td>\n                <td>« _C_ »</td>\n              </tr>\n              <tr>\n                <th>[[PendingAsyncDependencies]]</th>\n                <td>2 (_B_ and _C_)</td>\n                <td>1 (_D_)</td>\n                <td>2 (_D_ and _E_)</td>\n                <td>0</td>\n                <td>0</td>\n              </tr>\n            </table>\n          </emu-table>\n\n          <p>Let us assume that _E_ finishes executing first. When that happens, AsyncModuleExecutionFulfilled is called, _E_.[[Status]] is set to ~evaluated~ and _C_.[[PendingAsyncDependencies]] is decremented to become 1. The fields of the updated modules are as given in table-module-graph-cycle-async-fields-2.</p>\n\n          <emu-table id=\"table-module-graph-cycle-async-fields-2\" caption=\"Module fields after module _E_ finishes executing\">\n            <table>\n              <thead>\n                <tr>\n                  <th class=\"corner-cell\">\n                    <span class=\"column\">Field</span>\n                    <div class=\"slash\">\n                    </div>\n                    <span class=\"row\">Module</span>\n                  </th>\n                  <th>_C_</th>\n                  <th>_E_</th>\n                </tr>\n              </thead>\n              <tr>\n                <th>[[DFSAncestorIndex]]</th>\n                <td>0</td>\n                <td>4</td>\n              </tr>\n              <tr>\n                <th>[[Status]]</th>\n                <td>~evaluating-async~</td>\n                <td>~evaluated~</td>\n              </tr>\n              <tr>\n                <th>[[AsyncEvaluationOrder]]</th>\n                <td>3</td>\n                <td>~done~</td>\n              </tr>\n              <tr>\n                <th>[[AsyncParentModules]]</th>\n                <td>« _A_ »</td>\n                <td>« _C_ »</td>\n              </tr>\n              <tr>\n                <th>[[PendingAsyncDependencies]]</th>\n                <td>1 (_D_)</td>\n                <td>0</td>\n              </tr>\n            </table>\n          </emu-table>\n\n          <p>_D_ is next to finish (as it was the only module that was still executing). When that happens, AsyncModuleExecutionFulfilled is called again and _D_.[[Status]] is set to ~evaluated~. Its ancestors available for execution are _B_ (whose [[AsyncEvaluationOrder]] is 1) and _C_ (whose [[AsyncEvaluationOrder]] is 3), thus _B_ will be handled first: _B_.[[PendingAsyncDependencies]] is decremented to become 0, ExecuteAsyncModule is called on _B_, and it starts executing. _C_.[[PendingAsyncDependencies]] is also decremented to become 0, and _C_ starts executing (potentially in parallel to _B_ if _B_ contains an `await`). The fields of the updated modules are as given in table-module-graph-cycle-async-fields-3.</p>\n\n          <emu-table id=\"table-module-graph-cycle-async-fields-3\" caption=\"Module fields after module _D_ finishes executing\">\n            <table>\n              <thead>\n                <tr>\n                  <th class=\"corner-cell\">\n                    <span class=\"column\">Field</span>\n                    <div class=\"slash\">\n                    </div>\n                    <span class=\"row\">Module</span>\n                  </th>\n                  <th>_B_</th>\n                  <th>_C_</th>\n                  <th>_D_</th>\n                </tr>\n              </thead>\n              <tr>\n                <th>[[DFSAncestorIndex]]</th>\n                <td>0</td>\n                <td>0</td>\n                <td>0</td>\n              </tr>\n              <tr>\n                <th>[[Status]]</th>\n                <td>~evaluating-async~</td>\n                <td>~evaluating-async~</td>\n                <td>~evaluated~</td>\n              </tr>\n              <tr>\n                <th>[[AsyncEvaluationOrder]]</th>\n                <td>1</td>\n                <td>3</td>\n                <td>~done~</td>\n              </tr>\n              <tr>\n                <th>[[AsyncParentModules]]</th>\n                <td>« _A_ »</td>\n                <td>« _A_ »</td>\n                <td>« _B_, _C_ »</td>\n              </tr>\n              <tr>\n                <th>[[PendingAsyncDependencies]]</th>\n                <td>0</td>\n                <td>0</td>\n                <td>0</td>\n              </tr>\n            </table>\n          </emu-table>\n\n          <p>Let us assume that _C_ finishes executing next. When that happens, AsyncModuleExecutionFulfilled is called again, _C_.[[Status]] is set to ~evaluated~ and _A_.[[PendingAsyncDependencies]] is decremented to become 1. The fields of the updated modules are as given in table-module-graph-cycle-async-fields-4.</p>\n\n          <emu-table id=\"table-module-graph-cycle-async-fields-4\" caption=\"Module fields after module _C_ finishes executing\">\n            <table>\n              <thead>\n                <tr>\n                  <th class=\"corner-cell\">\n                    <span class=\"column\">Field</span>\n                    <div class=\"slash\">\n                    </div>\n                    <span class=\"row\">Module</span>\n                  </th>\n                  <th>_A_</th>\n                  <th>_C_</th>\n                </tr>\n              </thead>\n              <tr>\n                <th>[[DFSAncestorIndex]]</th>\n                <td>0</td>\n                <td>0</td>\n              </tr>\n              <tr>\n                <th>[[Status]]</th>\n                <td>~evaluating-async~</td>\n                <td>~evaluated~</td>\n              </tr>\n              <tr>\n                <th>[[AsyncEvaluationOrder]]</th>\n                <td>4</td>\n                <td>~done~</td>\n              </tr>\n              <tr>\n                <th>[[AsyncParentModules]]</th>\n                <td>« »</td>\n                <td>« _A_ »</td>\n              </tr>\n              <tr>\n                <th>[[PendingAsyncDependencies]]</th>\n                <td>1 (_B_)</td>\n                <td>0</td>\n              </tr>\n            </table>\n          </emu-table>\n\n          <p>Then, _B_ finishes executing. When that happens, AsyncModuleExecutionFulfilled is called again and _B_.[[Status]] is set to ~evaluated~. _A_.[[PendingAsyncDependencies]] is decremented to become 0, so ExecuteAsyncModule is called and it starts executing. The fields of the updated modules are as given in table-module-graph-cycle-async-fields-5.</p>\n\n          <emu-table id=\"table-module-graph-cycle-async-fields-5\" caption=\"Module fields after module _B_ finishes executing\">\n            <table>\n              <thead>\n                <tr>\n                  <th class=\"corner-cell\">\n                    <span class=\"column\">Field</span>\n                    <div class=\"slash\">\n                    </div>\n                    <span class=\"row\">Module</span>\n                  </th>\n                  <th>_A_</th>\n                  <th>_B_</th>\n                </tr>\n              </thead>\n              <tr>\n                <th>[[DFSAncestorIndex]]</th>\n                <td>0</td>\n                <td>0</td>\n              </tr>\n              <tr>\n                <th>[[Status]]</th>\n                <td>~evaluating-async~</td>\n                <td>~evaluated~</td>\n              </tr>\n              <tr>\n                <th>[[AsyncEvaluationOrder]]</th>\n                <td>4</td>\n                <td>~done~</td>\n              </tr>\n              <tr>\n                <th>[[AsyncParentModules]]</th>\n                <td>« »</td>\n                <td>« _A_ »</td>\n              </tr>\n              <tr>\n                <th>[[PendingAsyncDependencies]]</th>\n                <td>0</td>\n                <td>0</td>\n              </tr>\n            </table>\n          </emu-table>\n\n          <p>Finally, _A_ finishes executing. When that happens, AsyncModuleExecutionFulfilled is called again and _A_.[[Status]] is set to ~evaluated~. At this point, the Promise in _A_.[[TopLevelCapability]] (which was returned from _A_.Evaluate()) is resolved, and this concludes the handling of this module graph. The fields of the updated module are as given in table-module-graph-cycle-async-fields-6.</p>\n\n          <emu-table id=\"table-module-graph-cycle-async-fields-6\" caption=\"Module fields after module _A_ finishes executing\">\n            <table>\n              <thead>\n                <tr>\n                  <th class=\"corner-cell\">\n                    <span class=\"column\">Field</span>\n                    <div class=\"slash\">\n                    </div>\n                    <span class=\"row\">Module</span>\n                  </th>\n                  <th>_A_</th>\n                </tr>\n              </thead>\n              <tr>\n                <th>[[DFSAncestorIndex]]</th>\n                <td>0</td>\n              </tr>\n              <tr>\n                <th>[[Status]]</th>\n                <td>~evaluated~</td>\n              </tr>\n              <tr>\n                <th>[[AsyncEvaluationOrder]]</th>\n                <td>~done~</td>\n              </tr>\n              <tr>\n                <th>[[AsyncParentModules]]</th>\n                <td>« »</td>\n              </tr>\n              <tr>\n                <th>[[PendingAsyncDependencies]]</th>\n                <td>0</td>\n              </tr>\n            </table>\n          </emu-table>\n\n          <p>Alternatively, consider a failure case where _C_ fails execution and returns an error before _B_ has finished executing. When that happens, AsyncModuleExecutionRejected is called, which sets _C_.[[Status]] to ~evaluated~ and _C_.[[EvaluationError]] to the error. It then propagates this error to all of the AsyncParentModules by performing AsyncModuleExecutionRejected on each of them. The fields of the updated modules are as given in table-module-graph-cycle-async-fields-7.</p>\n\n          <emu-table id=\"table-module-graph-cycle-async-fields-7\" caption=\"Module fields after module _C_ finishes with an error\">\n            <table>\n              <thead>\n                <tr>\n                  <th class=\"corner-cell\">\n                    <span class=\"column\">Field</span>\n                    <div class=\"slash\">\n                    </div>\n                    <span class=\"row\">Module</span>\n                  </th>\n                  <th>_A_</th>\n                  <th>_C_</th>\n                </tr>\n              </thead>\n              <tr>\n                <th>[[DFSAncestorIndex]]</th>\n                <td>0</td>\n                <td>0</td>\n              </tr>\n              <tr>\n                <th>[[Status]]</th>\n                <td>~evaluated~</td>\n                <td>~evaluated~</td>\n              </tr>\n              <tr>\n                <th>[[AsyncEvaluationOrder]]</th>\n                <td>~done~</td>\n                <td>~done~</td>\n              </tr>\n              <tr>\n                <th>[[AsyncParentModules]]</th>\n                <td>« »</td>\n                <td>« _A_ »</td>\n              </tr>\n              <tr>\n                <th>[[PendingAsyncDependencies]]</th>\n                <td>1 (_B_)</td>\n                <td>0</td>\n              </tr>\n              <tr>\n                <th>[[EvaluationError]]</th>\n                <td>~empty~</td>\n                <td>_C_'s evaluation error</td>\n              </tr>\n            </table>\n          </emu-table>\n\n          <p>_A_ will be rejected with the same error as _C_ since _C_ will call AsyncModuleExecutionRejected on _A_ with _C_'s error. _A_.[[Status]] is set to ~evaluated~. At this point the Promise in _A_.[[TopLevelCapability]] (which was returned from _A_.Evaluate()) is rejected. The fields of the updated module are as given in table-module-graph-cycle-async-fields-8.</p>\n\n          <emu-table id=\"table-module-graph-cycle-async-fields-8\" caption=\"Module fields after module _A_ is rejected\">\n            <table>\n              <thead>\n                <tr>\n                  <th class=\"corner-cell\">\n                    <span class=\"column\">Field</span>\n                    <div class=\"slash\">\n                    </div>\n                    <span class=\"row\">Module</span>\n                  </th>\n                  <th>_A_</th>\n                </tr>\n              </thead>\n              <tr>\n                <th>[[DFSAncestorIndex]]</th>\n                <td>0</td>\n              </tr>\n              <tr>\n                <th>[[Status]]</th>\n                <td>~evaluated~</td>\n              </tr>\n              <tr>\n                <th>[[AsyncEvaluationOrder]]</th>\n                <td>~done~</td>\n              </tr>\n              <tr>\n                <th>[[AsyncParentModules]]</th>\n                <td>« »</td>\n              </tr>\n              <tr>\n                <th>[[PendingAsyncDependencies]]</th>\n                <td>0</td>\n              </tr>\n              <tr>\n                <th>[[EvaluationError]]</th>\n\n                <td>_C_'s Evaluation Error</td>\n              </tr>\n            </table>\n          </emu-table>\n\n          <p>Then, _B_ finishes executing without an error. When that happens, AsyncModuleExecutionFulfilled is called again and _B_.[[Status]] is set to ~evaluated~. GatherAvailableAncestors is called on _B_. However, _A_.[[CycleRoot]] is _A_ which has an evaluation error, so it will not be added to the returned _sortedExecList_ and AsyncModuleExecutionFulfilled will return without further processing. Any future importer of _B_ will resolve the rejection of _B_.[[CycleRoot]].[[EvaluationError]] from the evaluation error from _C_ that was set on the cycle root _A_. The fields of the updated modules are as given in table-module-graph-cycle-async-fields-9.</p>\n\n          <emu-table id=\"table-module-graph-cycle-async-fields-9\" caption=\"Module fields after module _B_ finishes executing in an erroring graph\">\n            <table>\n              <thead>\n                <tr>\n                  <th class=\"corner-cell\">\n                    <span class=\"column\">Field</span>\n                    <div class=\"slash\">\n                    </div>\n                    <span class=\"row\">Module</span>\n                  </th>\n                  <th>_A_</th>\n                  <th>_B_</th>\n                </tr>\n              </thead>\n              <tr>\n                <th>[[DFSAncestorIndex]]</th>\n                <td>0</td>\n                <td>0</td>\n              </tr>\n              <tr>\n                <th>[[Status]]</th>\n                <td>~evaluated~</td>\n                <td>~evaluated~</td>\n              </tr>\n              <tr>\n                <th>[[AsyncEvaluationOrder]]</th>\n                <td>4</td>\n                <td>1</td>\n              </tr>\n              <tr>\n                <th>[[AsyncParentModules]]</th>\n                <td>« »</td>\n                <td>« _A_ »</td>\n              </tr>\n              <tr>\n                <th>[[PendingAsyncDependencies]]</th>\n                <td>0</td>\n                <td>0</td>\n              </tr>\n              <tr>\n                <th>[[EvaluationError]]</th>\n                <td>_C_'s Evaluation Error</td>\n                <td>~empty~</td>\n              </tr>\n            </table>\n          </emu-table>\n        ","2.1.7":"<p>A <dfn id=\"sourctextmodule-record\" variants=\"Source Text Module Records\">Source Text Module Record</dfn> is used to represent information about a module that was defined from ECMAScript source text (11) that was parsed using the goal symbol |Module|. Its fields contain digested information about the names that are imported and exported by the module, and its concrete methods use these digests to link and evaluate the module.</p>\n\n        <p>A Source Text Module Record can exist in a module graph with other subclasses of the abstract Module Record type, and can participate in cycles with other subclasses of the Cyclic Module Record type.</p>\n\n        <p>In addition to the fields defined in table-cyclic-module-fields, Source Text Module Records have the additional fields listed in table-additional-fields-of-source-text-module-records. Each of these fields is initially set in ParseModule.</p>\n        <emu-table id=\"table-additional-fields-of-source-text-module-records\" caption=\"Additional Fields of Source Text Module Records\" oldids=\"table-38\">\n          <table>\n            <thead>\n              <tr>\n                <th>\n                  Field Name\n                </th>\n                <th>\n                  Value Type\n                </th>\n                <th>\n                  Meaning\n                </th>\n              </tr>\n            </thead>\n            <tr>\n              <td>\n                [[ECMAScriptCode]]\n              </td>\n              <td>\n                a Parse Node\n              </td>\n              <td>\n                The result of parsing the source text of this module using |Module| as the goal symbol.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[Context]]\n              </td>\n              <td>\n                an ECMAScript code execution context or ~empty~\n              </td>\n              <td>\n                The execution context associated with this module. It is ~empty~ until the module's environment has been initialized.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[ImportMeta]]\n              </td>\n              <td>\n                an Object or ~empty~\n              </td>\n              <td>\n                An object exposed through the `import.meta` meta property. It is ~empty~ until it is accessed by ECMAScript code.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[ImportEntries]]\n              </td>\n              <td>\n                a List of ImportEntry Records\n              </td>\n              <td>\n                A List of ImportEntry records derived from the code of this module.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[LocalExportEntries]]\n              </td>\n              <td>\n                a List of ExportEntry Records\n              </td>\n              <td>\n                A List of ExportEntry records derived from the code of this module that correspond to declarations that occur within the module.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[IndirectExportEntries]]\n              </td>\n              <td>\n                a List of ExportEntry Records\n              </td>\n              <td>\n                A List of ExportEntry records derived from the code of this module that correspond to reexported imports that occur within the module or exports from `export * as namespace` declarations.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[StarExportEntries]]\n              </td>\n              <td>\n                a List of ExportEntry Records\n              </td>\n              <td>\n                A List of ExportEntry records derived from the code of this module that correspond to `export *` declarations that occur within the module, not including `export * as namespace` declarations.\n              </td>\n            </tr>\n          </table>\n        </emu-table>\n        <p>An <dfn id=\"importentry-record\" variants=\"ImportEntry Records\">ImportEntry Record</dfn> is a Record that digests information about a single declarative import. Each ImportEntry Record has the fields defined in table-importentry-record-fields:</p>\n        <emu-table id=\"table-importentry-record-fields\" caption=\"ImportEntry Record Fields\" oldids=\"table-39\">\n          <table>\n            <thead>\n              <tr>\n                <th>\n                  Field Name\n                </th>\n                <th>\n                  Value Type\n                </th>\n                <th>\n                  Meaning\n                </th>\n              </tr>\n            </thead>\n            <tr>\n              <td>\n                [[ModuleRequest]]\n              </td>\n              <td>\n                a ModuleRequest Record\n              </td>\n              <td>\n                ModuleRequest Record representing the |ModuleSpecifier| and import attributes of the |ImportDeclaration|.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[ImportName]]\n              </td>\n              <td>\n                a String or ~namespace~\n              </td>\n              <td>\n                The name under which the desired binding is exported by the module identified by [[ModuleRequest]]. The value ~namespace~ indicates that the import request is for the target module's namespace object.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[LocalName]]\n              </td>\n              <td>\n                a String\n              </td>\n              <td>\n                The name that is used to locally access the imported value from within the importing module.\n              </td>\n            </tr>\n          </table>\n        </emu-table>\n        <emu-note>\n          <p>table-import-forms-mapping-to-importentry-records gives examples of ImportEntry records fields used to represent the syntactic import forms:</p>\n          <emu-table id=\"table-import-forms-mapping-to-importentry-records\" caption=\"Import Forms Mappings to ImportEntry Records\" informative oldids=\"table-40\">\n            <table>\n              <thead>\n                <tr>\n                  <th>\n                    Import Statement Form\n                  </th>\n                  <th>\n                    [[ModuleRequest]]\n                  </th>\n                  <th>\n                    [[ImportName]]\n                  </th>\n                  <th>\n                    [[LocalName]]\n                  </th>\n                </tr>\n              </thead>\n              <tr>\n                <td>\n                  `import v from \"mod\";`\n                </td>\n                <td>\n                  *\"mod\"*\n                </td>\n                <td>\n                  *\"default\"*\n                </td>\n                <td>\n                  *\"v\"*\n                </td>\n              </tr>\n              <tr>\n                <td>\n                  `import * as ns from \"mod\";`\n                </td>\n                <td>\n                  *\"mod\"*\n                </td>\n                <td>\n                  ~namespace~\n                </td>\n                <td>\n                  *\"ns\"*\n                </td>\n              </tr>\n              <tr>\n                <td>\n                  `import {x} from \"mod\";`\n                </td>\n                <td>\n                  *\"mod\"*\n                </td>\n                <td>\n                  *\"x\"*\n                </td>\n                <td>\n                  *\"x\"*\n                </td>\n              </tr>\n              <tr>\n                <td>\n                  `import {x as v} from \"mod\";`\n                </td>\n                <td>\n                  *\"mod\"*\n                </td>\n                <td>\n                  *\"x\"*\n                </td>\n                <td>\n                  *\"v\"*\n                </td>\n              </tr>\n              <tr>\n                <td>\n                  `import \"mod\";`\n                </td>\n                <td colspan=\"3\">\n                  An ImportEntry Record is not created.\n                </td>\n              </tr>\n            </table>\n          </emu-table>\n        </emu-note>\n        <p>An <dfn id=\"exportentry-record\" variants=\"ExportEntry Records\">ExportEntry Record</dfn> is a Record that digests information about a single declarative export. Each ExportEntry Record has the fields defined in table-exportentry-records:</p>\n        <emu-table id=\"table-exportentry-records\" caption=\"ExportEntry Record Fields\" oldids=\"table-41\">\n          <table>\n            <thead>\n              <tr>\n                <th>\n                  Field Name\n                </th>\n                <th>\n                  Value Type\n                </th>\n                <th>\n                  Meaning\n                </th>\n              </tr>\n            </thead>\n            <tr>\n              <td>\n                [[ExportName]]\n              </td>\n              <td>\n                a String or *null*\n              </td>\n              <td>\n                The name used to export this binding by this module.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[ModuleRequest]]\n              </td>\n              <td>\n                a ModuleRequest Record or *null*\n              </td>\n              <td>\n                The ModuleRequest Record representing the |ModuleSpecifier| and import attributes of the |ExportDeclaration|. *null* if the |ExportDeclaration| does not have a |ModuleSpecifier|.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[ImportName]]\n              </td>\n              <td>\n                a String, *null*, ~namespace~, or ~all-but-default~\n              </td>\n              <td>\n                The name under which the desired binding is exported by the module identified by [[ModuleRequest]]. *null* if the |ExportDeclaration| does not have a |ModuleSpecifier|. ~namespace~ is used for `export * as ns from \"mod\"` declarations. ~all-but-default~ is used for `export * from \"mod\"` declarations.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[LocalName]]\n              </td>\n              <td>\n                a String or *null*\n              </td>\n              <td>\n                The name that is used to locally access the exported value from within the importing module. *null* if the exported value is not locally accessible from within the module.\n              </td>\n            </tr>\n          </table>\n        </emu-table>\n        <emu-note>\n          <p>table-export-forms-mapping-to-exportentry-records gives examples of the ExportEntry record fields used to represent the syntactic export forms:</p>\n          <emu-table id=\"table-export-forms-mapping-to-exportentry-records\" caption=\"Export Forms Mappings to ExportEntry Records\" informative oldids=\"table-42\">\n            <table>\n              <thead>\n                <tr>\n                  <th>\n                    Export Statement Form\n                  </th>\n                  <th>\n                    [[ExportName]]\n                  </th>\n                  <th>\n                    [[ModuleRequest]]\n                  </th>\n                  <th>\n                    [[ImportName]]\n                  </th>\n                  <th>\n                    [[LocalName]]\n                  </th>\n                </tr>\n              </thead>\n              <tr>\n                <td>\n                  `export var v;`\n                </td>\n                <td>\n                  *\"v\"*\n                </td>\n                <td>\n                  *null*\n                </td>\n                <td>\n                  *null*\n                </td>\n                <td>\n                  *\"v\"*\n                </td>\n              </tr>\n              <tr>\n                <td>\n                  `export default function f() {}`\n                </td>\n                <td>\n                  *\"default\"*\n                </td>\n                <td>\n                  *null*\n                </td>\n                <td>\n                  *null*\n                </td>\n                <td>\n                  *\"f\"*\n                </td>\n              </tr>\n              <tr>\n                <td>\n                  `export default function () {}`\n                </td>\n                <td>\n                  *\"default\"*\n                </td>\n                <td>\n                  *null*\n                </td>\n                <td>\n                  *null*\n                </td>\n                <td>\n                  *\"\\*default\\*\"*\n                </td>\n              </tr>\n              <tr>\n                <td>\n                  `export default 42;`\n                </td>\n                <td>\n                  *\"default\"*\n                </td>\n                <td>\n                  *null*\n                </td>\n                <td>\n                  *null*\n                </td>\n                <td>\n                  *\"\\*default\\*\"*\n                </td>\n              </tr>\n              <tr>\n                <td>\n                  `export {x};`\n                </td>\n                <td>\n                  *\"x\"*\n                </td>\n                <td>\n                  *null*\n                </td>\n                <td>\n                  *null*\n                </td>\n                <td>\n                  *\"x\"*\n                </td>\n              </tr>\n              <tr>\n                <td>\n                  `export {v as x};`\n                </td>\n                <td>\n                  *\"x\"*\n                </td>\n                <td>\n                  *null*\n                </td>\n                <td>\n                  *null*\n                </td>\n                <td>\n                  *\"v\"*\n                </td>\n              </tr>\n              <tr>\n                <td>\n                  `export {x} from \"mod\";`\n                </td>\n                <td>\n                  *\"x\"*\n                </td>\n                <td>\n                  *\"mod\"*\n                </td>\n                <td>\n                  *\"x\"*\n                </td>\n                <td>\n                  *null*\n                </td>\n              </tr>\n              <tr>\n                <td>\n                  `export {v as x} from \"mod\";`\n                </td>\n                <td>\n                  *\"x\"*\n                </td>\n                <td>\n                  *\"mod\"*\n                </td>\n                <td>\n                  *\"v\"*\n                </td>\n                <td>\n                  *null*\n                </td>\n              </tr>\n              <tr>\n                <td>\n                  `export * from \"mod\";`\n                </td>\n                <td>\n                  *null*\n                </td>\n                <td>\n                  *\"mod\"*\n                </td>\n                <td>\n                  ~all-but-default~\n                </td>\n                <td>\n                  *null*\n                </td>\n              </tr>\n              <tr>\n                <td>\n                  `export * as ns from \"mod\";`\n                </td>\n                <td>\n                  *\"ns\"*\n                </td>\n                <td>\n                  *\"mod\"*\n                </td>\n                <td>\n                  ~namespace~\n                </td>\n                <td>\n                  *null*\n                </td>\n              </tr>\n            </table>\n          </emu-table>\n        </emu-note>\n        <p>The following definitions specify the required concrete methods and other abstract operations for Source Text Module Records</p>\n\n        ","2.1.7.1":"<dl class=\"header\">\n            <dt>description</dt>\n            <dd>It creates a Source Text Module Record based upon the result of parsing _sourceText_ as a |Module|.</dd>\n          </dl>\n          <emu-alg><ol><li>Let _body_ be ParseText(_sourceText_, |Module|).</li><li>If _body_ is a List of errors, return _body_.</li><li>Let _requestedModules_ be the ModuleRequests of _body_.</li><li>Let _importEntries_ be the ImportEntries of _body_.</li><li>Let _importedBoundNames_ be ImportedLocalNames(_importEntries_).</li><li>Let _indirectExportEntries_ be a new empty List.</li><li>Let _localExportEntries_ be a new empty List.</li><li>Let _starExportEntries_ be a new empty List.</li><li>Let _exportEntries_ be the ExportEntries of _body_.</li><li>For each ExportEntry Record _ee_ of _exportEntries_, do<ol><li>If _ee_.[[ModuleRequest]] is *null*, then<ol><li>If _importedBoundNames_ does not contain _ee_.[[LocalName]], then<ol><li>Append _ee_ to _localExportEntries_.</li></ol></li><li>Else,<ol><li>NOTE: When exporting a binding or namespace object which was originally imported from another module, the ExportEntry Record is rewritten to match the form it would have if the binding or namespace object had been re-exported directly from the original module rather than imported then exported. This allows conflicts which arise from exporting the same binding or namespace twice under the same name through `export * from` to be ignored rather than being treated as ambiguous in step step-resolveexport-conflict of <emu-xref href=\"#sec-resolveexport\">the ResolveExport concrete method of Source Text Module Records</emu-xref>.</li><li>Let _ie_ be the element of _importEntries_ whose [[LocalName]] is _ee_.[[LocalName]].</li><li>Append the ExportEntry Record { [[ModuleRequest]]: _ie_.[[ModuleRequest]], [[ImportName]]: _ie_.[[ImportName]], [[LocalName]]: *null*, [[ExportName]]: _ee_.[[ExportName]] } to _indirectExportEntries_.</li></ol></li></ol></li><li>Else if _ee_.[[ImportName]] is ~all-but-default~, then<ol><li>Assert: _ee_.[[ExportName]] is *null*.</li><li>Append _ee_ to _starExportEntries_.</li></ol></li><li>Else,<ol><li>Append _ee_ to _indirectExportEntries_.</li></ol></li></ol></li><li>Let _async_ be _body_ Contains `await`.</li><li>Return Source Text Module Record { [[Realm]]: _realm_, [[Environment]]: ~empty~, [[Namespace]]: ~empty~, [[CycleRoot]]: ~empty~, [[HasTLA]]: _async_, [[AsyncEvaluationOrder]]: ~unset~, [[TopLevelCapability]]: ~empty~, [[AsyncParentModules]]: « », [[PendingAsyncDependencies]]: ~empty~, [[Status]]: ~new~, [[EvaluationError]]: ~empty~, [[HostDefined]]: _hostDefined_, [[ECMAScriptCode]]: _body_, [[Context]]: ~empty~, [[ImportMeta]]: ~empty~, [[RequestedModules]]: _requestedModules_, [[LoadedModules]]: « », [[ImportEntries]]: _importEntries_, [[LocalExportEntries]]: _localExportEntries_, [[IndirectExportEntries]]: _indirectExportEntries_, [[StarExportEntries]]: _starExportEntries_, [[DFSAncestorIndex]]: ~empty~ }.</li></ol></emu-alg>\n          <emu-note>\n            <p>An implementation may parse module source text and analyse it for Early Error conditions prior to the evaluation of ParseModule for that module source text. However, the reporting of any errors must be deferred until the point where this specification actually performs ParseModule upon that source text.</p>\n          </emu-note>\n        ","2.1.7.2":"<p>The following are the concrete methods for Source Text Module Record that implement the corresponding Module Record abstract methods defined in table-abstract-methods-of-module-records.</p>\n\n          ","2.1.7.2.1":"<dl class=\"header\">\n              <dt>for</dt>\n              <dd>a Source Text Module Record _module_</dd>\n            </dl>\n            <emu-alg><ol><li>Assert: _module_.[[Status]] is not ~new~.</li><li>If _exportStarSet_ is not present, set _exportStarSet_ to a new empty List.</li><li>If _exportStarSet_ contains _module_, then<ol><li>Assert: We've reached the starting point of an `export *` circularity.</li><li>Return a new empty List.</li></ol></li><li>Append _module_ to _exportStarSet_.</li><li>Let _exportedNames_ be a new empty List.</li><li>For each ExportEntry Record _e_ of _module_.[[LocalExportEntries]], do<ol><li>Assert: _module_ provides the direct binding for this export.</li><li>Assert: _e_.[[ExportName]] is not *null*.</li><li>Append _e_.[[ExportName]] to _exportedNames_.</li></ol></li><li>For each ExportEntry Record _e_ of _module_.[[IndirectExportEntries]], do<ol><li>Assert: _module_ imports a specific binding for this export.</li><li>Assert: _e_.[[ExportName]] is not *null*.</li><li>Append _e_.[[ExportName]] to _exportedNames_.</li></ol></li><li>For each ExportEntry Record _e_ of _module_.[[StarExportEntries]], do<ol><li>Assert: _e_.[[ModuleRequest]] is not *null*.</li><li>Let _requestedModule_ be GetImportedModule(_module_, _e_.[[ModuleRequest]]).</li><li>Let _starNames_ be _requestedModule_.GetExportedNames(_exportStarSet_).</li><li>For each element _n_ of _starNames_, do<ol><li>If _n_ is not *\"default\"*, then<ol><li>If _exportedNames_ does not contain _n_, then<ol><li>Append _n_ to _exportedNames_.</li></ol></li></ol></li></ol></li></ol></li><li>Return _exportedNames_.</li></ol></emu-alg>\n            <emu-note>\n              <p>GetExportedNames does not filter out or throw an exception for names that have ambiguous star export bindings.</p>\n            </emu-note>\n          ","2.1.7.2.2":"<dl class=\"header\">\n              <dt>for</dt>\n              <dd>a Source Text Module Record _module_</dd>\n\n              <dt>description</dt>\n              <dd>\n                <p>ResolveExport attempts to resolve an imported binding to the actual defining module and local binding name. The defining module may be the module represented by the Module Record this method was invoked on or some other module that is imported by that module. The parameter _resolveSet_ is used to detect unresolved circular import/export paths. If a pair consisting of specific Module Record and _exportName_ is reached that is already in _resolveSet_, an import circularity has been encountered. Before recursively calling ResolveExport, a pair consisting of _module_ and _exportName_ is added to _resolveSet_.</p>\n                <p>If a defining module is found, a ResolvedBinding Record { [[Module]], [[BindingName]] } is returned. This record identifies the resolved binding of the originally requested export, unless this is the export of a namespace with no local binding. In this case, [[BindingName]] will be set to ~namespace~. If no definition was found or the request is found to be circular, *null* is returned. If the request is found to be ambiguous, ~ambiguous~ is returned.</p>\n              </dd>\n            </dl>\n\n            <emu-alg><ol><li>Assert: _module_.[[Status]] is not ~new~.</li><li>If _resolveSet_ is not present, set _resolveSet_ to a new empty List.</li><li>For each Record { [[Module]], [[ExportName]] } _r_ of _resolveSet_, do<ol><li>If _module_ and _r_.[[Module]] are the same Module Record and _exportName_ is _r_.[[ExportName]], then<ol><li>Assert: This is a circular import request.</li><li>Return *null*.</li></ol></li></ol></li><li>Append the Record { [[Module]]: _module_, [[ExportName]]: _exportName_ } to _resolveSet_.</li><li>For each ExportEntry Record _e_ of _module_.[[LocalExportEntries]], do<ol><li>If _e_.[[ExportName]] is _exportName_, then<ol><li>Assert: _module_ provides the direct binding for this export.</li><li>Return ResolvedBinding Record { [[Module]]: _module_, [[BindingName]]: _e_.[[LocalName]] }.</li></ol></li></ol></li><li>For each ExportEntry Record _e_ of _module_.[[IndirectExportEntries]], do<ol><li>If _e_.[[ExportName]] is _exportName_, then<ol><li>Assert: _e_.[[ModuleRequest]] is not *null*.</li><li>Let _importedModule_ be GetImportedModule(_module_, _e_.[[ModuleRequest]]).</li><li>If _e_.[[ImportName]] is ~namespace~, then<ol><li>Assert: _module_ does not provide the direct binding for this export.</li><li>Return ResolvedBinding Record { [[Module]]: _importedModule_, [[BindingName]]: ~namespace~ }.</li></ol></li><li>Assert: _module_ imports a specific binding for this export.</li><li>Assert: _e_.[[ImportName]] is a String.</li><li>Return _importedModule_.ResolveExport(_e_.[[ImportName]], _resolveSet_).</li></ol></li></ol></li><li>If _exportName_ is *\"default\"*, then<ol><li>Assert: A `default` export was not explicitly defined by this module.</li><li>Return *null*.</li><li>NOTE: A `default` export cannot be provided by an `export * from \"mod\"` declaration.</li></ol></li><li>Let _starResolution_ be *null*.</li><li>For each ExportEntry Record _e_ of _module_.[[StarExportEntries]], do<ol><li>Assert: _e_.[[ModuleRequest]] is not *null*.</li><li>Let _importedModule_ be GetImportedModule(_module_, _e_.[[ModuleRequest]]).</li><li>Let _resolution_ be _importedModule_.ResolveExport(_exportName_, _resolveSet_).</li><li>If _resolution_ is ~ambiguous~, return ~ambiguous~.</li><li>If _resolution_ is not *null*, then<ol><li>Assert: _resolution_ is a ResolvedBinding Record.</li><li>If _starResolution_ is *null*, then<ol><li>Set _starResolution_ to _resolution_.</li></ol></li><li>Else,<ol><li>Assert: There is more than one `*` export that includes the requested name.</li><li>If _resolution_.[[Module]] and _starResolution_.[[Module]] are not the same Module Record, return ~ambiguous~.</li><li>If _resolution_.[[BindingName]] is not _starResolution_.[[BindingName]], return ~ambiguous~.</li></ol></li></ol></li></ol></li><li>Return _starResolution_.</li></ol></emu-alg>\n          ","2.1.7.3":"<p>The following are the concrete methods for Source Text Module Record that implement the corresponding Cyclic Module Record abstract methods defined in table-cyclic-module-methods.</p>\n\n          ","2.1.7.3.1":"<dl class=\"header\">\n              <dt>for</dt>\n              <dd>a Source Text Module Record _module_</dd>\n            </dl>\n\n            <emu-alg><ol><li>For each ExportEntry Record _e_ of _module_.[[IndirectExportEntries]], do<ol><li>Assert: _e_.[[ExportName]] is not *null*.</li><li>Let _resolution_ be _module_.ResolveExport(_e_.[[ExportName]]).</li><li>If _resolution_ is either *null* or ~ambiguous~, throw a *SyntaxError* exception.</li><li>Assert: _resolution_ is a ResolvedBinding Record.</li></ol></li><li>Assert: All named exports from _module_ are resolvable.</li><li>Let _realm_ be _module_.[[Realm]].</li><li>Assert: _realm_ is not *undefined*.</li><li>Let _env_ be NewModuleEnvironment(_realm_.[[GlobalEnv]]).</li><li>Set _module_.[[Environment]] to _env_.</li><li>For each ImportEntry Record _in_ of _module_.[[ImportEntries]], do<ol><li>Let _importedModule_ be GetImportedModule(_module_, _in_.[[ModuleRequest]]).</li><li>If _in_.[[ImportName]] is ~namespace~, then<ol><li>Let _namespace_ be GetModuleNamespace(_importedModule_).</li><li>Perform ! _env_.CreateImmutableBinding(_in_.[[LocalName]], *true*).</li><li>Perform ! _env_.InitializeBinding(_in_.[[LocalName]], _namespace_).</li></ol></li><li>Else,<ol><li>Assert: _in_.[[ImportName]] is a String.</li><li>Let _resolution_ be _importedModule_.ResolveExport(_in_.[[ImportName]]).</li><li>If _resolution_ is either *null* or ~ambiguous~, throw a *SyntaxError* exception.</li><li>If _resolution_.[[BindingName]] is ~namespace~, then<ol><li>Let _namespace_ be GetModuleNamespace(_resolution_.[[Module]]).</li><li>Perform ! _env_.CreateImmutableBinding(_in_.[[LocalName]], *true*).</li><li>Perform ! _env_.InitializeBinding(_in_.[[LocalName]], _namespace_).</li></ol></li><li>Else,<ol><li>Perform CreateImportBinding(_env_, _in_.[[LocalName]], _resolution_.[[Module]], _resolution_.[[BindingName]]).</li></ol></li></ol></li></ol></li><li>Let _moduleContext_ be a new ECMAScript code execution context.</li><li>Set the Function of _moduleContext_ to *null*.</li><li>Assert: _module_.[[Realm]] is not *undefined*.</li><li>Set the Realm of _moduleContext_ to _module_.[[Realm]].</li><li>Set the ScriptOrModule of _moduleContext_ to _module_.</li><li>Set the VariableEnvironment of _moduleContext_ to _module_.[[Environment]].</li><li>Set the LexicalEnvironment of _moduleContext_ to _module_.[[Environment]].</li><li>Set the PrivateEnvironment of _moduleContext_ to *null*.</li><li>Set _module_.[[Context]] to _moduleContext_.</li><li>Push _moduleContext_ onto the execution context stack; _moduleContext_ is now the running execution context.</li><li>Let _code_ be _module_.[[ECMAScriptCode]].</li><li>Let _varDeclarations_ be the VarScopedDeclarations of _code_.</li><li>Let _declaredVarNames_ be a new empty List.</li><li>For each element _d_ of _varDeclarations_, do<ol><li>For each element _dn_ of the BoundNames of _d_, do<ol><li>If _declaredVarNames_ does not contain _dn_, then<ol><li>Perform ! _env_.CreateMutableBinding(_dn_, *false*).</li><li>Perform ! _env_.InitializeBinding(_dn_, *undefined*).</li><li>Append _dn_ to _declaredVarNames_.</li></ol></li></ol></li></ol></li><li>Let _lexDeclarations_ be the LexicallyScopedDeclarations of _code_.</li><li>Let _privateEnv_ be *null*.</li><li>For each element _d_ of _lexDeclarations_, do<ol><li>For each element _dn_ of the BoundNames of _d_, do<ol><li>If IsConstantDeclaration of _d_ is *true*, then<ol><li>Perform ! _env_.CreateImmutableBinding(_dn_, *true*).</li></ol></li><li>Else,<ol><li>Perform ! _env_.CreateMutableBinding(_dn_, *false*).</li></ol></li><li>If _d_ is either a |FunctionDeclaration|, a |GeneratorDeclaration|, an |AsyncFunctionDeclaration|, or an |AsyncGeneratorDeclaration|, then<ol><li>Let _fo_ be InstantiateFunctionObject of _d_ with arguments _env_ and _privateEnv_.</li><li>Perform ! _env_.InitializeBinding(_dn_, _fo_).</li></ol></li></ol></li></ol></li><li>Remove _moduleContext_ from the execution context stack.</li><li>Return ~unused~.</li></ol></emu-alg>\n          ","2.1.7.3.2":"<dl class=\"header\">\n              <dt>for</dt>\n              <dd>a Source Text Module Record _module_</dd>\n            </dl>\n\n            <emu-alg><ol><li>Assert: _module_ has been linked and declarations in its module environment have been instantiated.</li><li>Let _moduleContext_ be _module_.[[Context]].</li><li>If _module_.[[HasTLA]] is *false*, then<ol><li>Assert: _capability_ is not present.</li><li>Suspend the running execution context.</li><li>Push _moduleContext_ onto the execution context stack; _moduleContext_ is now the running execution context.</li><li>Let _result_ be Completion(Evaluation of _module_.[[ECMAScriptCode]]).</li><li>Suspend _moduleContext_ and remove it from the execution context stack.</li><li>Resume the context that is now on the top of the execution context stack as the running execution context.</li><li>If _result_ is an abrupt completion, then<ol><li>Return ? _result_.</li></ol></li></ol></li><li>Else,<ol><li>Assert: _capability_ is a PromiseCapability Record.</li><li>Perform AsyncBlockStart(_capability_, _module_.[[ECMAScriptCode]], _moduleContext_).</li></ol></li><li>Return ~unused~.</li></ol></emu-alg>\n          ","2.1.8":"<p>A <dfn variants=\"Synthetic Module Records\">Synthetic Module Record</dfn> is used to represent information about a module that is defined by specifications. Its exported names are statically defined at creation, while their corresponding values can change over time using SetSyntheticModuleExport. It has no imports or dependencies.</p>\n\n        <emu-note>A Synthetic Module Record could be used for defining a variety of module types: for example, JSON modules or CSS modules.</emu-note>\n\n        <p>In addition to the fields defined in table-module-record-fields Synthetic Module Records have the additional fields listed in table-synthetic-module-record-fields.</p>\n\n        <emu-table id=\"table-synthetic-module-record-fields\" caption=\"Additional Fields of Synthetic Module Records\">\n          <table>\n            <thead>\n              <tr>\n                <th>Field Name</th>\n                <th>Value Type</th>\n                <th>Meaning</th>\n              </tr>\n            </thead>\n            <tr>\n              <td>[[ExportNames]]</td>\n              <td>a List of Strings</td>\n              <td>The names of the exports of the module. This list does not contain duplicates.</td>\n            </tr>\n            <tr>\n              <td>[[EvaluationSteps]]</td>\n              <td>an Abstract Closure</td>\n              <td>The initialization logic to perform upon evaluation of the module, taking the Synthetic Module Record as its sole argument. It must not modify [[ExportNames]]. It may return an abrupt completion.</td>\n            </tr>\n          </table>\n        </emu-table>\n\n        ","2.1.8.1":"<dl class=\"header\">\n            <dt>description</dt>\n            <dd>It creates a Synthetic Module Record whose default export is _defaultExport_.</dd>\n          </dl>\n          <emu-alg><ol><li>Let _realm_ be the current Realm Record.</li><li>Let _setDefaultExport_ be a new Abstract Closure with parameters (_module_) that captures _defaultExport_ and performs the following steps when called:<ol><li>Perform SetSyntheticModuleExport(_module_, *\"default\"*, _defaultExport_).</li><li>Return NormalCompletion(~unused~).</li></ol></li><li>Return the Synthetic Module Record { [[Realm]]: _realm_, [[Environment]]: ~empty~, [[Namespace]]: ~empty~, [[HostDefined]]: *undefined*, [[ExportNames]]: « *\"default\"* », [[EvaluationSteps]]: _setDefaultExport_ }.</li></ol></emu-alg>\n        ","2.1.8.2":"<dl class=\"header\">\n            <dt>description</dt>\n            <dd></dd>\n          </dl>\n\n          <emu-alg><ol><li>Let _parseResult_ be ? ParseJSON(_source_).</li><li>Return CreateDefaultExportSyntheticModule(_parseResult_.[[Value]]).</li></ol></emu-alg>\n        ","2.1.8.3":"<dl class=\"header\">\n            <dt>description</dt>\n            <dd>It can be used to set or change the exported value for an existing export of a Synthetic Module Record.</dd>\n          </dl>\n\n          <emu-alg><ol><li>Assert: _module_.[[ExportNames]] contains _exportName_.</li><li>Let _envRec_ be _module_.[[Environment]].</li><li>Assert: _envRec_ is not ~empty~.</li><li>Perform ! _envRec_.SetMutableBinding(_exportName_, _exportValue_, *true*).</li><li>Return ~unused~.</li></ol></emu-alg>\n        ","2.1.8.4":"<p>The following are the concrete methods for Synthetic Module Record that implement the corresponding Module Record abstract methods defined in table-abstract-methods-of-module-records.</p>\n\n          ","2.1.8.4.1":"<dl class=\"header\">\n              <dt>for</dt>\n              <dd>a Synthetic Module Record _module_</dd>\n            </dl>\n\n            <emu-alg><ol><li>NOTE: This implementation of LoadRequestedModules does not use _hostDefined_.</li><li>Return ! PromiseResolve(%Promise%, *undefined*).</li></ol></emu-alg>\n\n            <emu-note>\n              Synthetic Module Records have no dependencies.\n            </emu-note>\n          ","2.1.8.4.2":"<dl class=\"header\">\n              <dt>for</dt>\n              <dd>a Synthetic Module Record _module_</dd>\n            </dl>\n\n            <emu-alg><ol><li>NOTE: This implementation of GetExportedNames does not use _exportStarSet_.</li><li>Return _module_.[[ExportNames]].</li></ol></emu-alg>\n          ","2.1.8.4.3":"<dl class=\"header\">\n              <dt>for</dt>\n              <dd>a Synthetic Module Record _module_</dd>\n            </dl>\n\n            <emu-alg><ol><li>NOTE: This implementation of ResolveExport does not use _resolveSet_.</li><li>If _module_.[[ExportNames]] does not contain _exportName_, return *null*.</li><li>Return ResolvedBinding Record { [[Module]]: _module_, [[BindingName]]: _exportName_ }.</li></ol></emu-alg>\n          ","2.1.8.4.4":"<dl class=\"header\">\n              <dt>for</dt>\n              <dd>a Synthetic Module Record _module_</dd>\n            </dl>\n\n            <emu-alg><ol><li>Let _realm_ be _module_.[[Realm]].</li><li>Let _env_ be NewModuleEnvironment(_realm_.[[GlobalEnv]]).</li><li>Set _module_.[[Environment]] to _env_.</li><li>For each String _exportName_ of _module_.[[ExportNames]], do<ol><li>Perform ! _env_.CreateMutableBinding(_exportName_, *false*).</li><li>Perform ! _env_.InitializeBinding(_exportName_, *undefined*).</li></ol></li><li>Return NormalCompletion(~unused~).</li></ol></emu-alg>\n          ","2.1.8.4.5":"<dl class=\"header\">\n              <dt>for</dt>\n              <dd>a Synthetic Module Record _module_</dd>\n            </dl>\n\n            <emu-alg><ol><li>Let _moduleContext_ be a new ECMAScript code execution context.</li><li>Set the Function of _moduleContext_ to *null*.</li><li>Set the Realm of _moduleContext_ to _module_.[[Realm]].</li><li>Set the ScriptOrModule of _moduleContext_ to _module_.</li><li>Set the VariableEnvironment of _moduleContext_ to _module_.[[Environment]].</li><li>Set the LexicalEnvironment of _moduleContext_ to _module_.[[Environment]].</li><li>Suspend the running execution context.</li><li>Push _moduleContext_ onto the execution context stack; _moduleContext_ is now the running execution context.</li><li>Let _steps_ be _module_.[[EvaluationSteps]].</li><li>Let _result_ be Completion(_steps_(_module_)).</li><li>Suspend _moduleContext_ and remove it from the execution context stack.</li><li>Resume the context that is now on the top of the execution context stack as the running execution context.</li><li>Let _pc_ be ! NewPromiseCapability(%Promise%).</li><li>IfAbruptRejectPromise(_result_, _pc_).</li><li>Perform ! Call(_pc_.[[Resolve]], *undefined*, « *undefined* »).</li><li>Return _pc_.[[Promise]].</li></ol></emu-alg>\n          ","2.1.9":"<dl class=\"header\">\n          <dt>description</dt>\n          <dd></dd>\n        </dl>\n\n        <emu-alg><ol><li>Let _records_ be a List consisting of each LoadedModuleRequest Record _r_ of _referrer_.[[LoadedModules]] such that ModuleRequestsEqual(_r_, _request_) is *true*.</li><li>Assert: _records_ has exactly one element, since LoadRequestedModules has completed successfully on _referrer_ prior to invoking this abstract operation.</li><li>Let _record_ be the sole element of _records_.</li><li>Return _record_.[[Module]].</li></ol></emu-alg>\n      ","2.1.10":"<dl class=\"header\">\n          <dt>description</dt>\n          <dd></dd>\n        </dl>\n\n        <emu-note id=\"note-HostLoadImportedModule-referrer-Realm-Record\">\n          <p>An example of when _referrer_ can be a Realm Record is in a web browser host. There, if a user clicks on a control given by</p>\n\n          <pre><code class=\"html\">&lt;button type=\"button\" onclick=\"import('./foo.mjs')\"&gt;Click me&lt;/button&gt;</code></pre>\n\n          <p>there will be no active script or module at the time the <emu-xref href=\"#sec-import-calls\">`import()`</emu-xref> expression runs. More generally, this can happen in any situation where the host pushes execution contexts with *null* ScriptOrModule components onto the execution context stack.</p>\n        </emu-note>\n\n        <p>An implementation of HostLoadImportedModule must conform to the following requirements:</p>\n        <ul>\n          <li>\n            The host environment must perform FinishLoadingImportedModule(_referrer_, _moduleRequest_, _payload_, _result_), where _result_ is either a normal completion containing the loaded Module Record or a throw completion, either synchronously or asynchronously.\n          </li>\n          <li>\n            <p>If this operation is called multiple times with two (_referrer_, _moduleRequest_) pairs such that:</p>\n            <ul>\n              <li>the first _referrer_ is the same as the second _referrer_;</li>\n              <li>ModuleRequestsEqual(the first _moduleRequest_, the second _moduleRequest_) is *true*;</li>\n            </ul>\n            <p>and it performs FinishLoadingImportedModule(_referrer_, _moduleRequest_, _payload_, _result_) where _result_ is a normal completion, then it must perform FinishLoadingImportedModule(_referrer_, _moduleRequest_, _payload_, _result_) with the same _result_ each time.</p>\n          </li>\n          <li>\n            <p>If _moduleRequest_.[[Attributes]] has an entry _entry_ such that _entry_.[[Key]] is *\"type\"* and _entry_.[[Value]] is *\"json\"*, when the host environment performs FinishLoadingImportedModule(_referrer_, _moduleRequest_, _payload_, _result_), _result_ must either be the Completion Record returned by an invocation of ParseJSONModule or a throw completion.</p>\n          </li>\n          <li>\n            The operation must treat _payload_ as an opaque value to be passed through to FinishLoadingImportedModule.\n          </li>\n        </ul>\n\n        <p>The actual process performed is host-defined, but typically consists of performing whatever I/O operations are necessary to load the appropriate Module Record. Multiple different (_referrer_, _moduleRequest_.[[Specifier]], _moduleRequest_.[[Attributes]]) triples may map to the same Module Record instance. The actual mapping semantics is host-defined but typically a normalization process is applied to _specifier_ as part of the mapping process. A typical normalization process would include actions such as expansion of relative and abbreviated path specifiers.</p>\n\n        <emu-note>\n          <p>The above text requires that hosts support JSON modules when imported with `type: \"json\"` (and HostLoadImportedModule completes normally), but it does not prohibit hosts from supporting JSON modules when imported without `type: \"json\"`.</p>\n        </emu-note>\n      ","2.1.11":"<dl class=\"header\">\n          <dt>description</dt>\n          <dd></dd>\n        </dl>\n        <emu-alg><ol><li>If _result_ is a normal completion, then<ol><li>If _referrer_.[[LoadedModules]] contains a LoadedModuleRequest Record _record_ such that ModuleRequestsEqual(_record_, _moduleRequest_) is *true*, then<ol><li>Assert: _record_.[[Module]] and _result_.[[Value]] are the same Module Record.</li></ol></li><li>Else,<ol><li>Append the LoadedModuleRequest Record { [[Specifier]]: _moduleRequest_.[[Specifier]], [[Attributes]]: _moduleRequest_.[[Attributes]], [[Module]]: _result_.[[Value]] } to _referrer_.[[LoadedModules]].</li></ol></li></ol></li><li>If _payload_ is a GraphLoadingState Record, then<ol><li>Perform ContinueModuleLoading(_payload_, _result_).</li></ol></li><li>Else,<ol><li>Perform ContinueDynamicImport(_payload_, _result_).</li></ol></li><li>Return ~unused~.</li></ol></emu-alg>\n      ","2.1.12":"<dl class=\"header\">\n          <dt>description</dt>\n          <dd></dd>\n        </dl>\n        <emu-alg><ol><li>Let _supported_ be HostGetSupportedImportAttributes().</li><li>For each ImportAttribute Record _attribute_ of _attributes_, do<ol><li>If _supported_ does not contain _attribute_.[[Key]], return *false*.</li></ol></li><li>Return *true*.</li></ol></emu-alg>\n\n        ","2.1.12.1":"<dl class=\"header\">\n            <dt>description</dt>\n            <dd>It allows host environments to specify which import attributes they support. Only attributes with supported keys will be provided to the host.</dd>\n          </dl>\n\n          <p>An implementation of HostGetSupportedImportAttributes must conform to the following requirements:</p>\n\n          <ul>\n            <li>It must return a List of Strings, each indicating a supported attribute.</li>\n\n            <li>Each time this operation is called, it must return the same List with the same contents in the same order.</li>\n          </ul>\n\n          <p>The default implementation of HostGetSupportedImportAttributes is to return a new empty List.</p>\n\n          <emu-note>The purpose of requiring the host to specify its supported import attributes, rather than passing all attributes to the host and letting it then choose which ones it wants to handle, is to ensure that unsupported attributes are handled in a consistent way across different hosts.</emu-note>\n        ","2.1.13":"<dl class=\"header\">\n          <dt>description</dt>\n          <dd>It retrieves the Module Namespace Object representing _module_'s exports, lazily creating it the first time it was requested, and storing it in _module_.[[Namespace]] for future retrieval.</dd>\n        </dl>\n\n        <emu-alg><ol><li>Assert: If _module_ is a Cyclic Module Record, then _module_.[[Status]] is not ~new~ or ~unlinked~.</li><li>Let _namespace_ be _module_.[[Namespace]].</li><li>If _namespace_ is ~empty~, then<ol><li>Let _exportedNames_ be _module_.GetExportedNames().</li><li>Let _unambiguousNames_ be a new empty List.</li><li>For each element _name_ of _exportedNames_, do<ol><li>Let _resolution_ be _module_.ResolveExport(_name_).</li><li>If _resolution_ is a ResolvedBinding Record, append _name_ to _unambiguousNames_.</li></ol></li><li>Set _namespace_ to ModuleNamespaceCreate(_module_, _unambiguousNames_).</li></ol></li><li>Return _namespace_.</li></ol></emu-alg>\n        <emu-note>\n          <p>GetModuleNamespace never throws. Instead, unresolvable names are simply excluded from the namespace at this point. They will lead to a real linking error later unless they are all ambiguous star exports that are not explicitly requested anywhere.</p>\n        </emu-note>\n      ","2.1.14":"<pre class=\"emu-grammar\">Module : [empty]</pre>\n        <emu-alg><ol><li>Return *undefined*.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ModuleBody : ModuleItemList</pre>\n        <emu-alg><ol><li>Let _result_ be Completion(Evaluation of |ModuleItemList|).</li><li>If _result_ is a normal completion and _result_.[[Value]] is ~empty~, then<ol><li>Return *undefined*.</li></ol></li><li>Return ? _result_.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ModuleItemList : ModuleItemList ModuleItem</pre>\n        <emu-alg><ol><li>Let _sl_ be ? Evaluation of |ModuleItemList|.</li><li>Let _s_ be Completion(Evaluation of |ModuleItem|).</li><li>Return ? UpdateEmpty(_s_, _sl_).</li></ol></emu-alg>\n        <emu-note>\n          <p>The value of a |ModuleItemList| is the value of the last value-producing item in the |ModuleItemList|.</p>\n        </emu-note>\n        <pre class=\"emu-grammar\">ModuleItem : ImportDeclaration</pre>\n        <emu-alg><ol><li>Return ~empty~.</li></ol></emu-alg>\n      ","2.2":"<h2>Syntax</h2>\n      <pre class=\"emu-grammar\">ImportDeclaration :\n  `import` ImportClause FromClause WithClause? `;`\n  `import` ModuleSpecifier WithClause? `;`\n\nImportClause :\n  ImportedDefaultBinding\n  NameSpaceImport\n  NamedImports\n  ImportedDefaultBinding `,` NameSpaceImport\n  ImportedDefaultBinding `,` NamedImports\n\nImportedDefaultBinding :\n  ImportedBinding\n\nNameSpaceImport :\n  `*` `as` ImportedBinding\n\nNamedImports :\n  `{` `}`\n  `{` ImportsList `}`\n  `{` ImportsList `,` `}`\n\nFromClause :\n  `from` ModuleSpecifier\n\nImportsList :\n  ImportSpecifier\n  ImportsList `,` ImportSpecifier\n\nImportSpecifier :\n  ImportedBinding\n  ModuleExportName `as` ImportedBinding\n\nModuleSpecifier :\n  StringLiteral\n\nImportedBinding :\n  BindingIdentifier[~Yield, +Await]\n\nWithClause :\n  `with` `{` `}`\n  `with` `{` WithEntries `,`? `}`\n\nWithEntries :\n  AttributeKey `:` StringLiteral\n  AttributeKey `:` StringLiteral `,` WithEntries\n\nAttributeKey :\n  IdentifierName\n  StringLiteral</pre>\n\n      ","2.2.1":"<pre class=\"emu-grammar\">ModuleItem : ImportDeclaration</pre>\n        <ul>\n          <li>\n            It is a Syntax Error if the BoundNames of |ImportDeclaration| contains any duplicate entries.\n          </li>\n        </ul>\n\n        <pre class=\"emu-grammar\">WithClause : `with` `{` WithEntries `,`? `}`</pre>\n        <ul>\n          <li>\n            It is a Syntax Error if WithClauseToAttributes of |WithClause| has two different entries _a_ and _b_ such that _a_.[[Key]] is _b_.[[Key]].\n          </li>\n        </ul>\n      ","2.2.2":"<dl class=\"header\">\n        </dl>\n        <pre class=\"emu-grammar\">Module : [empty]</pre>\n        <emu-alg><ol><li>Return a new empty List.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ModuleItemList : ModuleItemList ModuleItem</pre>\n        <emu-alg><ol><li>Let _entries1_ be the ImportEntries of |ModuleItemList|.</li><li>Let _entries2_ be the ImportEntries of |ModuleItem|.</li><li>Return the list-concatenation of _entries1_ and _entries2_.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ModuleItem :\n  ExportDeclaration\n  StatementListItem</pre>\n        <emu-alg><ol><li>Return a new empty List.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ImportDeclaration : `import` ImportClause FromClause WithClause? `;`</pre>\n        <emu-alg><ol><li>Let _module_ be the sole element of the ModuleRequests of |ImportDeclaration|.</li><li>Return the ImportEntriesForModule of |ImportClause| with argument _module_.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ImportDeclaration : `import` ModuleSpecifier WithClause? `;`</pre>\n        <emu-alg><ol><li>Return a new empty List.</li></ol></emu-alg>\n      ","2.2.3":"<dl class=\"header\">\n        </dl>\n        <pre class=\"emu-grammar\">ImportClause : ImportedDefaultBinding `,` NameSpaceImport</pre>\n        <emu-alg><ol><li>Let _entries1_ be the ImportEntriesForModule of |ImportedDefaultBinding| with argument _module_.</li><li>Let _entries2_ be the ImportEntriesForModule of |NameSpaceImport| with argument _module_.</li><li>Return the list-concatenation of _entries1_ and _entries2_.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ImportClause : ImportedDefaultBinding `,` NamedImports</pre>\n        <emu-alg><ol><li>Let _entries1_ be the ImportEntriesForModule of |ImportedDefaultBinding| with argument _module_.</li><li>Let _entries2_ be the ImportEntriesForModule of |NamedImports| with argument _module_.</li><li>Return the list-concatenation of _entries1_ and _entries2_.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ImportedDefaultBinding : ImportedBinding</pre>\n        <emu-alg><ol><li>Let _localName_ be the sole element of the BoundNames of |ImportedBinding|.</li><li>Let _defaultEntry_ be the ImportEntry Record { [[ModuleRequest]]: _module_, [[ImportName]]: *\"default\"*, [[LocalName]]: _localName_ }.</li><li>Return « _defaultEntry_ ».</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">NameSpaceImport : `*` `as` ImportedBinding</pre>\n        <emu-alg><ol><li>Let _localName_ be the StringValue of |ImportedBinding|.</li><li>Let _entry_ be the ImportEntry Record { [[ModuleRequest]]: _module_, [[ImportName]]: ~namespace~, [[LocalName]]: _localName_ }.</li><li>Return « _entry_ ».</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">NamedImports : `{` `}`</pre>\n        <emu-alg><ol><li>Return a new empty List.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ImportsList : ImportsList `,` ImportSpecifier</pre>\n        <emu-alg><ol><li>Let _specs1_ be the ImportEntriesForModule of |ImportsList| with argument _module_.</li><li>Let _specs2_ be the ImportEntriesForModule of |ImportSpecifier| with argument _module_.</li><li>Return the list-concatenation of _specs1_ and _specs2_.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ImportSpecifier : ImportedBinding</pre>\n        <emu-alg><ol><li>Let _localName_ be the sole element of the BoundNames of |ImportedBinding|.</li><li>Let _entry_ be the ImportEntry Record { [[ModuleRequest]]: _module_, [[ImportName]]: _localName_, [[LocalName]]: _localName_ }.</li><li>Return « _entry_ ».</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ImportSpecifier : ModuleExportName `as` ImportedBinding</pre>\n        <emu-alg><ol><li>Let _importName_ be the StringValue of |ModuleExportName|.</li><li>Let _localName_ be the StringValue of |ImportedBinding|.</li><li>Let _entry_ be the ImportEntry Record { [[ModuleRequest]]: _module_, [[ImportName]]: _importName_, [[LocalName]]: _localName_ }.</li><li>Return « _entry_ ».</li></ol></emu-alg>\n      ","2.2.4":"<dl class=\"header\">\n        </dl>\n\n        <pre class=\"emu-grammar\">WithClause : `with` `{` `}`</pre>\n        <emu-alg><ol><li>Return a new empty List.</li></ol></emu-alg>\n\n        <pre class=\"emu-grammar\">WithClause : `with` `{` WithEntries `,`? `}`</pre>\n        <emu-alg><ol><li>Let _attributes_ be WithClauseToAttributes of |WithEntries|.</li><li>Sort _attributes_ according to the lexicographic order of their [[Key]] field, treating the value of each such field as a sequence of UTF-16 code unit values. NOTE: This sorting is observable only in that hosts are prohibited from changing behaviour based on the order in which attributes are enumerated.</li><li>Return _attributes_.</li></ol></emu-alg>\n\n        <pre class=\"emu-grammar\">WithEntries : AttributeKey `:` StringLiteral</pre>\n        <emu-alg><ol><li>Let _key_ be the PropName of |AttributeKey|.</li><li>Let _entry_ be the ImportAttribute Record { [[Key]]: _key_, [[Value]]: the SV of |StringLiteral| }.</li><li>Return « _entry_ ».</li></ol></emu-alg>\n\n        <pre class=\"emu-grammar\">WithEntries : AttributeKey `:` StringLiteral `,` WithEntries</pre>\n        <emu-alg><ol><li>Let _key_ be the PropName of |AttributeKey|.</li><li>Let _entry_ be the ImportAttribute Record { [[Key]]: _key_, [[Value]]: the SV of |StringLiteral| }.</li><li>Let _rest_ be WithClauseToAttributes of |WithEntries|.</li><li>Return the list-concatenation of « _entry_ » and _rest_.</li></ol></emu-alg>\n      ","2.3":"<h2>Syntax</h2>\n      <pre class=\"emu-grammar\">ExportDeclaration :\n  `export` ExportFromClause FromClause WithClause? `;`\n  `export` NamedExports `;`\n  `export` VariableStatement[~Yield, +Await]\n  `export` Declaration[~Yield, +Await]\n  `export` `default` HoistableDeclaration[~Yield, +Await, +Default]\n  `export` `default` ClassDeclaration[~Yield, +Await, +Default]\n  `export` `default` [lookahead &notin; { `function`, `async` [no LineTerminator here] `function`, `class` }] AssignmentExpression[+In, ~Yield, +Await] `;`\n\nExportFromClause :\n  `*`\n  `*` `as` ModuleExportName\n  NamedExports\n\nNamedExports :\n  `{` `}`\n  `{` ExportsList `}`\n  `{` ExportsList `,` `}`\n\nExportsList :\n  ExportSpecifier\n  ExportsList `,` ExportSpecifier\n\nExportSpecifier :\n  ModuleExportName\n  ModuleExportName `as` ModuleExportName</pre>\n\n      ","2.3.1":"<pre class=\"emu-grammar\">ExportDeclaration : `export` NamedExports `;`</pre>\n        <ul>\n          <li>\n            It is a Syntax Error if the ReferencedBindings of |NamedExports| contains any |StringLiteral|s.\n          </li>\n          <li>\n            For each |IdentifierName| _n_ in the ReferencedBindings of |NamedExports|: It is a Syntax Error if the StringValue of _n_ is a |ReservedWord| or the StringValue of _n_ is one of *\"implements\"*, *\"interface\"*, *\"let\"*, *\"package\"*, *\"private\"*, *\"protected\"*, *\"public\"*, or *\"static\"*.\n          </li>\n        </ul>\n        <emu-note>\n          <p>The above rule means that each ReferencedBindings of |NamedExports| is treated as an |IdentifierReference|.</p>\n        </emu-note>\n      ","2.3.2":"<dl class=\"header\">\n        </dl>\n        <emu-note>\n          <p>ExportedBindings are the locally bound names that are explicitly associated with a |Module|'s ExportedNames.</p>\n        </emu-note>\n        <pre class=\"emu-grammar\">ModuleItemList : ModuleItemList ModuleItem</pre>\n        <emu-alg><ol><li>Let _names1_ be the ExportedBindings of |ModuleItemList|.</li><li>Let _names2_ be the ExportedBindings of |ModuleItem|.</li><li>Return the list-concatenation of _names1_ and _names2_.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ModuleItem :\n  ImportDeclaration\n  StatementListItem</pre>\n        <emu-alg><ol><li>Return a new empty List.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration : `export` ExportFromClause FromClause WithClause? `;`</pre>\n        <emu-alg><ol><li>Return a new empty List.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration : `export` NamedExports `;`</pre>\n        <emu-alg><ol><li>Return the ExportedBindings of |NamedExports|.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration : `export` VariableStatement</pre>\n        <emu-alg><ol><li>Return the BoundNames of |VariableStatement|.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration : `export` Declaration</pre>\n        <emu-alg><ol><li>Return the BoundNames of |Declaration|.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration :\n  `export` `default` HoistableDeclaration\n  `export` `default` ClassDeclaration\n  `export` `default` AssignmentExpression `;`</pre>\n        <emu-alg><ol><li>Return the BoundNames of this |ExportDeclaration|.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">NamedExports : `{` `}`</pre>\n        <emu-alg><ol><li>Return a new empty List.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportsList : ExportsList `,` ExportSpecifier</pre>\n        <emu-alg><ol><li>Let _names1_ be the ExportedBindings of |ExportsList|.</li><li>Let _names2_ be the ExportedBindings of |ExportSpecifier|.</li><li>Return the list-concatenation of _names1_ and _names2_.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportSpecifier : ModuleExportName</pre>\n        <emu-alg><ol><li>Return a List whose sole element is the StringValue of |ModuleExportName|.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportSpecifier : ModuleExportName `as` ModuleExportName</pre>\n        <emu-alg><ol><li>Return a List whose sole element is the StringValue of the first |ModuleExportName|.</li></ol></emu-alg>\n      ","2.3.3":"<dl class=\"header\">\n        </dl>\n        <emu-note>\n          <p>ExportedNames are the externally visible names that a |Module| explicitly maps to one of its local name bindings.</p>\n        </emu-note>\n        <pre class=\"emu-grammar\">ModuleItemList : ModuleItemList ModuleItem</pre>\n        <emu-alg><ol><li>Let _names1_ be the ExportedNames of |ModuleItemList|.</li><li>Let _names2_ be the ExportedNames of |ModuleItem|.</li><li>Return the list-concatenation of _names1_ and _names2_.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ModuleItem : ExportDeclaration</pre>\n        <emu-alg><ol><li>Return the ExportedNames of |ExportDeclaration|.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ModuleItem :\n  ImportDeclaration\n  StatementListItem</pre>\n        <emu-alg><ol><li>Return a new empty List.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration : `export` ExportFromClause FromClause WithClause? `;`</pre>\n        <emu-alg><ol><li>Return the ExportedNames of |ExportFromClause|.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportFromClause : `*`</pre>\n        <emu-alg><ol><li>Return a new empty List.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportFromClause : `*` `as` ModuleExportName</pre>\n        <emu-alg><ol><li>Return a List whose sole element is the StringValue of |ModuleExportName|.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportFromClause : NamedExports</pre>\n        <emu-alg><ol><li>Return the ExportedNames of |NamedExports|.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration : `export` VariableStatement</pre>\n        <emu-alg><ol><li>Return the BoundNames of |VariableStatement|.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration : `export` Declaration</pre>\n        <emu-alg><ol><li>Return the BoundNames of |Declaration|.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration :\n  `export` `default` HoistableDeclaration\n  `export` `default` ClassDeclaration\n  `export` `default` AssignmentExpression `;`</pre>\n        <emu-alg><ol><li>Return « *\"default\"* ».</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">NamedExports : `{` `}`</pre>\n        <emu-alg><ol><li>Return a new empty List.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportsList : ExportsList `,` ExportSpecifier</pre>\n        <emu-alg><ol><li>Let _names1_ be the ExportedNames of |ExportsList|.</li><li>Let _names2_ be the ExportedNames of |ExportSpecifier|.</li><li>Return the list-concatenation of _names1_ and _names2_.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportSpecifier : ModuleExportName</pre>\n        <emu-alg><ol><li>Return a List whose sole element is the StringValue of |ModuleExportName|.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportSpecifier : ModuleExportName `as` ModuleExportName</pre>\n        <emu-alg><ol><li>Return a List whose sole element is the StringValue of the second |ModuleExportName|.</li></ol></emu-alg>\n      ","2.3.4":"<dl class=\"header\">\n        </dl>\n        <pre class=\"emu-grammar\">Module : [empty]</pre>\n        <emu-alg><ol><li>Return a new empty List.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ModuleItemList : ModuleItemList ModuleItem</pre>\n        <emu-alg><ol><li>Let _entries1_ be the ExportEntries of |ModuleItemList|.</li><li>Let _entries2_ be the ExportEntries of |ModuleItem|.</li><li>Return the list-concatenation of _entries1_ and _entries2_.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ModuleItem :\n  ImportDeclaration\n  StatementListItem</pre>\n        <emu-alg><ol><li>Return a new empty List.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration : `export` ExportFromClause FromClause WithClause? `;`</pre>\n        <emu-alg><ol><li>Let _module_ be the sole element of the ModuleRequests of |ExportDeclaration|.</li><li>Return the ExportEntriesForModule of |ExportFromClause| with argument _module_.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration : `export` NamedExports `;`</pre>\n        <emu-alg><ol><li>Return the ExportEntriesForModule of |NamedExports| with argument *null*.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration : `export` VariableStatement</pre>\n        <emu-alg><ol><li>Let _entries_ be a new empty List.</li><li>Let _names_ be the BoundNames of |VariableStatement|.</li><li>For each element _name_ of _names_, do<ol><li>Append the ExportEntry Record { [[ModuleRequest]]: *null*, [[ImportName]]: *null*, [[LocalName]]: _name_, [[ExportName]]: _name_ } to _entries_.</li></ol></li><li>Return _entries_.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration : `export` Declaration</pre>\n        <emu-alg><ol><li>Let _entries_ be a new empty List.</li><li>Let _names_ be the BoundNames of |Declaration|.</li><li>For each element _name_ of _names_, do<ol><li>Append the ExportEntry Record { [[ModuleRequest]]: *null*, [[ImportName]]: *null*, [[LocalName]]: _name_, [[ExportName]]: _name_ } to _entries_.</li></ol></li><li>Return _entries_.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration : `export` `default` HoistableDeclaration</pre>\n        <emu-alg><ol><li>Let _names_ be the BoundNames of |HoistableDeclaration|.</li><li>Let _localName_ be the sole element of _names_.</li><li>Return a List whose sole element is a new ExportEntry Record { [[ModuleRequest]]: *null*, [[ImportName]]: *null*, [[LocalName]]: _localName_, [[ExportName]]: *\"default\"* }.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration : `export` `default` ClassDeclaration</pre>\n        <emu-alg><ol><li>Let _names_ be the BoundNames of |ClassDeclaration|.</li><li>Let _localName_ be the sole element of _names_.</li><li>Return a List whose sole element is a new ExportEntry Record { [[ModuleRequest]]: *null*, [[ImportName]]: *null*, [[LocalName]]: _localName_, [[ExportName]]: *\"default\"* }.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration : `export` `default` AssignmentExpression `;`</pre>\n        <emu-alg><ol><li>Let _entry_ be the ExportEntry Record { [[ModuleRequest]]: *null*, [[ImportName]]: *null*, [[LocalName]]: *\"\\*default\\*\"*, [[ExportName]]: *\"default\"* }.</li><li>Return « _entry_ ».</li></ol></emu-alg>\n        <emu-note>\n          <p>*\"\\*default\\*\"* is used within this specification as a synthetic name for anonymous default export values. See <emu-xref href=\"#note-star-default-star\">this note</emu-xref> for more details.</p>\n        </emu-note>\n      ","2.3.5":"<dl class=\"header\">\n        </dl>\n        <pre class=\"emu-grammar\">ExportFromClause : `*`</pre>\n        <emu-alg><ol><li>Let _entry_ be the ExportEntry Record { [[ModuleRequest]]: _module_, [[ImportName]]: ~all-but-default~, [[LocalName]]: *null*, [[ExportName]]: *null* }.</li><li>Return « _entry_ ».</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportFromClause : `*` `as` ModuleExportName</pre>\n        <emu-alg><ol><li>Let _exportName_ be the StringValue of |ModuleExportName|.</li><li>Let _entry_ be the ExportEntry Record { [[ModuleRequest]]: _module_, [[ImportName]]: ~namespace~, [[LocalName]]: *null*, [[ExportName]]: _exportName_ }.</li><li>Return « _entry_ ».</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">NamedExports : `{` `}`</pre>\n        <emu-alg><ol><li>Return a new empty List.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportsList : ExportsList `,` ExportSpecifier</pre>\n        <emu-alg><ol><li>Let _specs1_ be the ExportEntriesForModule of |ExportsList| with argument _module_.</li><li>Let _specs2_ be the ExportEntriesForModule of |ExportSpecifier| with argument _module_.</li><li>Return the list-concatenation of _specs1_ and _specs2_.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportSpecifier : ModuleExportName</pre>\n        <emu-alg><ol><li>Let _sourceName_ be the StringValue of |ModuleExportName|.</li><li>If _module_ is *null*, then<ol><li>Let _localName_ be _sourceName_.</li><li>Let _importName_ be *null*.</li></ol></li><li>Else,<ol><li>Let _localName_ be *null*.</li><li>Let _importName_ be _sourceName_.</li></ol></li><li>Return a List whose sole element is a new ExportEntry Record { [[ModuleRequest]]: _module_, [[ImportName]]: _importName_, [[LocalName]]: _localName_, [[ExportName]]: _sourceName_ }.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportSpecifier : ModuleExportName `as` ModuleExportName</pre>\n        <emu-alg><ol><li>Let _sourceName_ be the StringValue of the first |ModuleExportName|.</li><li>Let _exportName_ be the StringValue of the second |ModuleExportName|.</li><li>If _module_ is *null*, then<ol><li>Let _localName_ be _sourceName_.</li><li>Let _importName_ be *null*.</li></ol></li><li>Else,<ol><li>Let _localName_ be *null*.</li><li>Let _importName_ be _sourceName_.</li></ol></li><li>Return a List whose sole element is a new ExportEntry Record { [[ModuleRequest]]: _module_, [[ImportName]]: _importName_, [[LocalName]]: _localName_, [[ExportName]]: _exportName_ }.</li></ol></emu-alg>\n      ","2.3.6":"<dl class=\"header\">\n        </dl>\n        <pre class=\"emu-grammar\">NamedExports : `{` `}`</pre>\n        <emu-alg><ol><li>Return a new empty List.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportsList : ExportsList `,` ExportSpecifier</pre>\n        <emu-alg><ol><li>Let _names1_ be the ReferencedBindings of |ExportsList|.</li><li>Let _names2_ be the ReferencedBindings of |ExportSpecifier|.</li><li>Return the list-concatenation of _names1_ and _names2_.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportSpecifier : ModuleExportName `as` ModuleExportName</pre>\n        <emu-alg><ol><li>Return the ReferencedBindings of the first |ModuleExportName|.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ModuleExportName : IdentifierName</pre>\n        <emu-alg><ol><li>Return a List whose sole element is the |IdentifierName|.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ModuleExportName : StringLiteral</pre>\n        <emu-alg><ol><li>Return a List whose sole element is the |StringLiteral|.</li></ol></emu-alg>\n      ","2.3.7":"<pre class=\"emu-grammar\">ExportDeclaration :\n  `export` ExportFromClause FromClause WithClause? `;`\n  `export` NamedExports `;`</pre>\n        <emu-alg><ol><li>Return ~empty~.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration : `export` VariableStatement</pre>\n        <emu-alg><ol><li>Return ? Evaluation of |VariableStatement|.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration : `export` Declaration</pre>\n        <emu-alg><ol><li>Return ? Evaluation of |Declaration|.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration : `export` `default` HoistableDeclaration</pre>\n        <emu-alg><ol><li>Return ? Evaluation of |HoistableDeclaration|.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration : `export` `default` ClassDeclaration</pre>\n        <emu-alg><ol><li>Let _value_ be ? BindingClassDeclarationEvaluation of |ClassDeclaration|.</li><li>Let _className_ be the sole element of the BoundNames of |ClassDeclaration|.</li><li>If _className_ is *\"\\*default\\*\"*, then<ol><li>Let _env_ be the running execution context's LexicalEnvironment.</li><li>Perform ? InitializeBoundName(*\"\\*default\\*\"*, _value_, _env_).</li></ol></li><li>Return ~empty~.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration : `export` `default` AssignmentExpression `;`</pre>\n        <emu-alg><ol><li>If IsAnonymousFunctionDefinition(|AssignmentExpression|) is *true*, then<ol><li>Let _value_ be ? NamedEvaluation of |AssignmentExpression| with argument *\"default\"*.</li></ol></li><li>Else,<ol><li>Let _rhs_ be ? Evaluation of |AssignmentExpression|.</li><li>Let _value_ be ? GetValue(_rhs_).</li></ol></li><li>Let _env_ be the running execution context's LexicalEnvironment.</li><li>Perform ? InitializeBoundName(*\"\\*default\\*\"*, _value_, _env_).</li><li>Return ~empty~.</li></ol></emu-alg>\n      "};
export function Sec({ id }) {
  const html = sections[id] ?? '';
  return <div className="ecma-spec" dangerouslySetInnerHTML={{ __html: html }} />;
}
